import React from 'react';
import { useAdminLeads, useDeleteLead } from '../../hooks/useAdminQueries';
import { useToast } from './Toast';
import { Button } from '../ui/Button';
import { Card, CardContent } from '../ui/Card';

interface AdminAllLeadsTabProps {
  setIsNewLeadOpen: (val: boolean) => void;
  setSelectedLead: (lead: any) => void;
  showConfirm: (msg: string, onConfirm: () => void) => void;
}

export default function AdminAllLeadsTab({ setIsNewLeadOpen, setSelectedLead, showConfirm }: AdminAllLeadsTabProps) {
  const { data: leads = [], isLoading } = useAdminLeads();
  const deleteLeadMutation = useDeleteLead();
  const { showToast } = useToast();

  if (isLoading) {
    return <div className="p-8 text-center text-gray-400">Carregando leads...</div>;
  }

  return (
    <div className="page active">
      <div className="u-section-header">
        <div className="u-syne-title">Todos os Leads</div>
        <Button variant="gold" onClick={() => setIsNewLeadOpen(true)}>+ Novo Lead</Button>
      </div>
      <Card>
        <CardContent className="p-0 overflow-x-auto">
          <table className="tbl">
            <thead>
              <tr>
                <th>Lead / Cliente</th>
                <th>Servi├ºo / Cidade</th>
                <th>Valor</th>
                <th>Temperatura</th>
                <th>Status</th>
                <th>Criado em</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {leads.map(l => (
                <tr key={l.id} className="u-cursor-pointer" onClick={() => setSelectedLead(l)}>
                  <td><b>{l.clients?.name || l.name || 'Lead s/ Nome'}</b></td>
                  <td>{l.service_type} ÔÇó {l.city}</td>
                  <td className="u-text-gold">${l.estimated_value ? Number(l.estimated_value).toLocaleString() : 'N/D'}</td>
                  <td>
                    {l.urgency === 'hot' && <span className="urg hot">QUENTE</span>}
                    {l.urgency === 'warm' && <span className="urg warm">MORNO</span>}
                    {l.urgency === 'cool' && <span className="urg cool">FRIO</span>}
                  </td>
                  <td><span className="status-b sb-draft">{l.status}</span></td>
                  <td>
                    <div style={{ fontSize: '0.75rem', color: 'var(--text)' }}>
                      {new Date(l.created_at || '').toLocaleDateString('pt-BR')}
                      <br />
                      <span style={{ color: 'var(--t2)' }}>
                        {new Date(l.created_at || '').toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}
                      </span>
                    </div>
                  </td>
                  <td onClick={e => e.stopPropagation()}>
                    <Button 
                      variant="ghost" 
                      className="px-2 py-1 text-[.85rem] text-danger border-transparent" 
                      onClick={() => {
                        showConfirm(`Deseja excluir o lead "${l.clients?.name || l.name}"?`, async () => {
                          try {
                            await deleteLeadMutation.mutateAsync(l.id);
                            showToast('Lead exclu├¡do com sucesso!');
                          } catch (err: any) {
                            showToast('Erro: ' + err.message);
                          }
                        });
                      }}
                    >
                      ­ƒùæ´©Å
                    </Button>
                  </td>
                </tr>
              ))}

              {leads.length === 0 && (
                <tr><td colSpan={7} className="text-center p-4 text-gray-400">Nenhum lead encontrado.</td></tr>
              )}
            </tbody>
          </table>
        </CardContent>
      </Card>
    </div>
  );
}

import React from 'react';
import { useAdminLandingPages, useDeleteLandingPage } from '../../hooks/useAdminQueries';
import { useToast } from './Toast';
import { Button } from '../ui/Button';
import { Card, CardContent } from '../ui/Card';

interface AdminLandingPagesTabProps {
  setIsLPOpen: (val: boolean) => void;
  showConfirm: (msg: string, onConfirm: () => void) => void;
}

export default function AdminLandingPagesTab({ setIsLPOpen, showConfirm }: AdminLandingPagesTabProps) {
  const { data: landingPages = [], isLoading } = useAdminLandingPages();
  const deleteLPMutation = useDeleteLandingPage();
  const { showToast } = useToast();

  const toggleLPStatus = (lp: any) => {
    // Left as a placeholder, the original file had this logic inline but incomplete
    showToast('A├º├úo atualizar status ser├í vinculada ao React Query');
  };

  if (isLoading) {
    return <div className="p-8 text-center text-gray-400">Carregando Landing Pages...</div>;
  }

  return (
    <div className="page active">
      <div className="u-section-header">
        <div className="u-syne-title">Landing Pages</div>
        <Button variant="gold" onClick={() => setIsLPOpen(true)}>+ Nova LP</Button>
      </div>
      <Card>
        <CardContent className="p-0 overflow-x-auto">
          <table className="tbl">
            <thead>
              <tr>
                <th style={{ width: '18%' }}>P├ígina (Cidade)</th>
                <th style={{ width: '12%' }}>Status</th>
                <th style={{ width: '14%' }}>Visitantes</th>
                <th style={{ width: '14%' }}>Leads Gerados</th>
                <th style={{ width: '14%' }}>Convers├úo</th>
                <th style={{ width: '28%', textAlign: 'center' }}>A├º├úo</th>
              </tr>
            </thead>
            <tbody>
              {landingPages.length === 0 && (
                <tr><td colSpan={6} className="u-empty-state">Nenhuma LP encontrada.</td></tr>
              )}
              {landingPages.map(lp => {
                const convRate = (lp.visitors ?? 0) > 0 ? Math.round(((lp.leads_count ?? 0) / (lp.visitors ?? 1)) * 100) : 0;
                return (
                  <tr key={lp.id}>
                    <td>
                      <b>{lp.name}</b>
                      <div style={{ fontSize: '0.7rem', color: 'var(--t2)' }}>{lp.city}</div>
                    </td>
                    <td>
                      <span 
                        className={`status-b ${lp.status === 'live' ? 'sb-live' : 'sb-draft'}`} 
                        style={{ cursor: 'pointer' }} 
                        title="Clique para alternar o status" 
                        onClick={() => toggleLPStatus(lp)}
                      >
                        {(lp.status || 'draft').toUpperCase()}
                      </span>
                    </td>
                    <td>{lp.visitors || 0}</td>
                    <td>{lp.leads_count || 0}</td>
                    <td><div style={{ fontFamily: "'DM Mono',monospace", color: 'var(--green)' }}>{convRate}%</div></td>
                    <td>
                      <div style={{ display: 'flex', gap: '12px', justifyContent: 'center', alignItems: 'center' }}>
                        <Button 
                          variant="ghost" 
                          className="px-3.5 py-1.5 text-[.75rem]" 
                          onClick={() => {
                            navigator.clipboard.writeText(`https://bravohomes.com/lp/${(lp.city || '').toLowerCase().replace(/\s+/g, '-')}`);
                            showToast('Link da LP copiado para a ├írea de transfer├¬ncia!');
                          }}
                        >
                          Link
                        </Button>
                        <Button 
                          variant="ghost" 
                          className="px-3.5 py-1.5 text-[.75rem]" 
                          onClick={() => showToast('Construtor visual de LP em breve!')}
                        >
                          Editar
                        </Button>
                        <Button 
                          variant="ghost" 
                          className="px-3.5 py-1.5 text-[0.95rem] text-danger border-transparent" 
                          onClick={() => {
                            showConfirm(`Deseja excluir a LP "${lp.name}"?`, async () => {
                              try {
                                await deleteLPMutation.mutateAsync(lp.id);
                                showToast('Landing Page exclu├¡da com sucesso!');
                              } catch (err: any) {
                                showToast('Erro: ' + err.message);
                              }
                            });
                          }}
                        >
                          ­ƒùæ´©Å
                        </Button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </CardContent>
      </Card>
    </div>
  );
}

import React from 'react';
import { useAdminProjects, useAdminLeads } from '../../hooks/useAdminQueries';
import { Card, CardContent, CardHeader, CardTitle } from '../ui/Card';
import { Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

interface AdminOverviewTabProps {
  setActiveTab: (tab: string) => void;
}

export default function AdminOverviewTab({ setActiveTab }: AdminOverviewTabProps) {
  const { data: projects = [], isLoading: loadingProjects } = useAdminProjects();
  const { data: leads = [], isLoading: loadingLeads } = useAdminLeads();

  const loadingDb = loadingProjects || loadingLeads;

  if (loadingDb) {
    return (
      <div className="page active">
        <div className="kpi-grid">
          {[1,2,3,4].map(i => <div key={i} className="skeleton skeleton-kpi"></div>)}
        </div>
        <div className="g2" style={{marginTop:'14px'}}>
          <div className="skeleton skeleton-card"></div>
          <div className="skeleton skeleton-card"></div>
        </div>
      </div>
    );
  }

  const totalRevenue = projects.reduce((acc, p) => acc + (Number(p.contract_value) || 0), 0);
  const activeProjectsCount = projects.filter(p => p.status === 'active').length;
  const activeLeadsCount = leads.length;
  const schedulingLeadsCount = leads.filter(l => l.status === 'scheduling').length;

  const currentYear = new Date().getFullYear();
  const monthlyRevenue = new Array(12).fill(0);
  projects.forEach(p => {
    if (p.created_at) {
      const d = new Date(p.created_at);
      if (d.getFullYear() === currentYear) {
        monthlyRevenue[d.getMonth()] += (Number(p.contract_value) || 0);
      }
    }
  });
  const chartLabels = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const leadsPerSource = leads.reduce((acc, l) => {
    const source = (l.source && l.source.trim() !== '') ? l.source : 'Desconhecido';
    acc[source] = (acc[source] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const totalLeadsWithSource = leads.length || 1;
  const sourceColors = ['var(--gold)', 'var(--blue)', 'var(--green)', 'var(--red)', 'var(--orange)', 'var(--purple)'];
  const sourceElements = (Object.entries(leadsPerSource) as [string, number][])
    .sort((a, b) => b[1] - a[1])
    .map(([source, count], idx) => {
      const color = sourceColors[idx % sourceColors.length];
      const percentage = Math.round((count / totalLeadsWithSource) * 100);
      const niceSourceName = source === 'manual-admin' ? 'Manual' : source;
      return (
        <div key={source} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.8rem', textTransform: 'capitalize' }}>
            <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: color }}></div>{niceSourceName}
          </div>
          <div style={{ fontFamily: "'DM Mono',monospace", fontSize: '0.75rem' }}>
            {percentage}% ┬À {Number(count)} leads
          </div>
        </div>
      );
    });

  return (
    <div className="page active">
      <div className="kpi-grid">
        <div className="kpi gold">
          <div className="kl">Receita Total (Obras)</div>
          <div className="kv">${totalRevenue.toLocaleString()}</div>
          <div className="kc">Dos contratos assinados</div>
        </div>
        <div className="kpi blue">
          <div className="kl">Leads Ativos</div>
          <div className="kv">{activeLeadsCount}</div>
          <div className="kc">Total no painel</div>
        </div>
        <div className="kpi green">
          <div className="kl">Obras em andamento</div>
          <div className="kv">{activeProjectsCount}</div>
          <div className="kc">Em execu├º├úo</div>
        </div>
        <div className="kpi red">
          <div className="kl">Visitas (Agendamentos)</div>
          <div className="kv">{schedulingLeadsCount}</div>
          <div className="kc">{schedulingLeadsCount > 0 ? 'Leads agendados' : 'Nenhuma no momento'}</div>
        </div>
      </div>

      <div className="g2">
        <Card>
          <CardHeader><CardTitle>Receita Mensal {currentYear}</CardTitle></CardHeader>
          <CardContent style={{ height: '160px', padding: '10px 18px' }}>
            <Bar 
              data={{
                labels: chartLabels,
                datasets: [{
                  label: 'Receita ($)',
                  data: monthlyRevenue,
                  backgroundColor: '#C9943A',
                  borderRadius: 4,
                }]
              }} 
              options={{
                responsive: true,
                maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: { 
                  y: { display: false, grid: { display: false } },
                  x: { grid: { display: false }, ticks: { color: '#9A9690', font: { size: 10, family: 'Inter' } }, border: { display: false } }
                }
              }} 
            />
          </CardContent>
        </Card>
        <Card>
          <CardHeader><CardTitle>Leads por Fonte</CardTitle></CardHeader>
          <CardContent style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {sourceElements.length > 0 ? sourceElements : (
              <div style={{ fontSize: '0.8rem', color: 'var(--t3)' }}>Nenhum lead com fonte rastreada.</div>
            )}
          </CardContent>
        </Card>
      </div>

      <div className="g2">
        <Card>
          <CardHeader>
            <CardTitle>Projetos em Andamento</CardTitle>
            <span className="ca" onClick={() => setActiveTab('projects')} style={{cursor: 'pointer'}}>Ver todos ÔåÆ</span>
          </CardHeader>
          <CardContent style={{ padding: 0 }}>
            <table className="tbl">
              <thead><tr><th>Cliente</th><th>Progresso</th><th>Entrega</th></tr></thead>
              <tbody>
                {projects.length === 0 && (
                  <tr><td colSpan={3} className="u-empty-state">Nenhum projeto encontrado.</td></tr>
                )}
                {projects.slice(0, 3).map((p: any) => (
                  <tr key={p.id} className="u-cursor-pointer" onClick={() => setActiveTab('projects')}>
                    <td>
                      <div style={{ fontWeight: 600 }}>{p.name || 'Projeto sem nome'}</div>
                      <div style={{ fontSize: '0.72rem', color: 'var(--t2)' }}>{p.service_type || 'Servi├ºo'} ┬À ${p.contract_value || '0'}</div>
                    </td>
                    <td style={{ width: '90px' }}>
                      <div className="prog-bar">
                        <div className="prog-fill" style={{ width: `${p.progress || 0}%` }}></div>
                      </div>
                      <div style={{ fontFamily: "'DM Mono',monospace", fontSize: '0.6rem', color: 'var(--gold)', marginTop: '3px' }}>
                        {p.progress || 0}%
                      </div>
                    </td>
                    <td style={{ fontFamily: "'DM Mono',monospace", fontSize: '0.7rem', color: 'var(--orange)' }}>
                      {p.deadline ? new Date(p.deadline).toLocaleDateString() : 'N/D'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </CardContent>
        </Card>

        <Card>
          <CardHeader><CardTitle>Atividade Recente</CardTitle></CardHeader>
          <CardContent style={{ padding: '0 18px' }}>
            {leads.slice(0, 3).map((l: any, i: number) => {
              const created = new Date(l.created_at);
              const now = new Date();
              const diffMs = now.getTime() - created.getTime();
              const diffMin = Math.floor(diffMs / 60000);
              const diffH = Math.floor(diffMin / 60);
              const isToday = created.toDateString() === now.toDateString();
              const isYesterday = created.toDateString() === new Date(now.getTime() - 86400000).toDateString();
              let timeLabel = '';
              if (diffMin < 1) timeLabel = 'Agora';
              else if (diffMin < 60) timeLabel = `${diffMin} min`;
              else if (diffH < 24 && isToday) timeLabel = `${diffH}h`;
              else if (isYesterday) timeLabel = `Ontem ${created.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}`;
              else timeLabel = created.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }) + ' ' + created.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

              return (
                <div className="log-item" key={l.id || i}>
                  <div className="log-date">{timeLabel}</div>
                  <div className="log-text">
                    Novo lead ÔÇó <strong>{l.clients?.name || l.name || 'Desconhecido'}</strong> via {l.source || 'Manual'} ÔÇö {l.service_type} {l.estimated_value ? `$${l.estimated_value}` : ''}
                  </div>
                </div>
              );
            })}
            {leads.length === 0 && (
              <>
                <div className="log-item"><div className="log-date">AGORA</div><div className="log-text">Aguardando atividades</div></div>
              </>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { useAdminLeads, useUpdateLeadStatus } from '../../hooks/useAdminQueries';
import { Button } from '../ui/Button';

interface AdminPipelineTabProps {
  setIsNewLeadOpen: (val: boolean) => void;
  setSelectedLead: (lead: any) => void;
}

export default function AdminPipelineTab({ setIsNewLeadOpen, setSelectedLead }: AdminPipelineTabProps) {
  const { data: leads = [], isLoading } = useAdminLeads();
  const updateStatus = useUpdateLeadStatus();

  const handleDragStart = (e: React.DragEvent, leadId: string) => {
    e.dataTransfer.setData('leadId', leadId);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = async (e: React.DragEvent, newStatus: string) => {
    e.preventDefault();
    const leadId = e.dataTransfer.getData('leadId');
    if (!leadId) return;

    try {
      await updateStatus.mutateAsync({ leadId, status: newStatus });
    } catch (err) {
      console.error('Failed to update status', err);
    }
  };

  if (isLoading) {
    return <div className="p-8 text-center text-gray-400">Carregando pipeline...</div>;
  }

  const activeLeadsCount = leads.length;

  return (
    <div className="page active">
      <div style={{ marginBottom: 16, display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
        <div>
          <div style={{ fontSize: '0.62rem', color: 'var(--t3)', letterSpacing: '1px', textTransform: 'uppercase', marginBottom: '3px' }}>
            {activeLeadsCount} leads ativos
          </div>
          <div style={{ fontWeight: 700, fontSize: '1.05rem' }}>Pipeline de Leads</div>
        </div>
        <Button variant="gold" onClick={() => setIsNewLeadOpen(true)}>+ Novo Lead</Button>
      </div>

      <div className="kanban">
        {['new', 'contacted', 'scheduling', 'proposal', 'closed'].map(statusGroup => {
          const statusTitles: Record<string, string> = {
            'new': 'Novos',
            'contacted': 'Em Contato',
            'scheduling': 'Agendamento / Visita',
            'proposal': 'Proposta',
            'closed': 'Fechados Ô£ô'
          };
          const colLeads = leads.filter(l => l.status === statusGroup);

          return (
            <div 
              className="kol" 
              key={statusGroup}
              onDragOver={handleDragOver}
              onDrop={(e) => handleDrop(e, statusGroup)}
            >
              <div className="kol-h">
                {statusTitles[statusGroup]}
                <span className="kol-n" style={statusGroup === 'closed' ? { background: 'var(--green)', color: '#fff' } : {}}>
                  {colLeads.length}
                </span>
              </div>

              {colLeads.map((l: any) => (
                <div 
                  className="lead-c" 
                  draggable 
                  key={l.id}
                  onDragStart={(e) => handleDragStart(e, l.id)}
                  onClick={() => setSelectedLead(l)}
                >
                  <div className="lc-name">{l.clients?.name || l.name || 'Lead s/ Nome'}</div>
                  <div className="lc-srv">{l.service_type || 'Servi├ºo G'} ┬À {l.city || 'Local ND'}</div>
                  <div className="lc-foot">
                    <span className="lc-val">{l.estimated_value ? `$${Number(l.estimated_value).toLocaleString()}` : 'Valor tbd'}</span>
                    {l.urgency === 'hot' && <span className="urg hot" style={{ background: 'rgba(231,76,60,0.15)', color: 'var(--red)' }}>QUENTE</span>}
                    {l.urgency === 'warm' && <span className="urg warm" style={{ background: 'rgba(230,126,34,0.15)', color: 'var(--orange)' }}>MORNO</span>}
                    {l.urgency === 'cool' && <span className="urg cool" style={{ background: 'rgba(52,152,219,0.15)', color: 'var(--blue)' }}>FRIO</span>}
                  </div>
                </div>
              ))}

              {colLeads.length === 0 && <div className="empty-state" style={{ fontSize: '0.8rem', padding: '10px' }}>Vazio</div>}
            </div>
          );
        })}
      </div>
    </div>
  );
}

import React from 'react';
import { useAdminProjects, useDeleteProject } from '../../hooks/useAdminQueries';
import { useToast } from './Toast';
import { Button } from '../ui/Button';
import { Card, CardContent } from '../ui/Card';

interface AdminProjectsTabProps {
  handleCreateProject: () => void;
  setNewProjectForm: (form: any) => void;
  setEditingProjectId: (id: string | null) => void;
  setIsNewProjectOpen: (val: boolean) => void;
  showConfirm: (msg: string, onConfirm: () => void) => void;
}

export default function AdminProjectsTab({ 
  handleCreateProject, 
  setNewProjectForm, 
  setEditingProjectId, 
  setIsNewProjectOpen,
  showConfirm 
}: AdminProjectsTabProps) {
  const { data: projects = [], isLoading } = useAdminProjects();
  const deleteProjectMutation = useDeleteProject();
  const { showToast } = useToast();

  if (isLoading) {
    return <div className="p-8 text-center text-gray-400">Carregando projetos...</div>;
  }

  return (
    <div className="page active">
      <div className="u-section-header">
        <div className="u-syne-title">Projetos Ativos ÔÇö Vis├úo Admin</div>
        <Button variant="gold" onClick={handleCreateProject}>Novo Projeto</Button>
      </div>
      <Card>
        <CardContent className="p-0 overflow-x-auto">
          <table className="tbl">
            <thead>
              <tr>
                <th>Cliente</th>
                <th>Servi├ºo</th>
                <th>Valor</th>
                <th>Progresso</th>
                <th>Status</th>
                <th style={{ textAlign: 'center' }}>A├º├úo</th>
              </tr>
            </thead>
            <tbody>
              {projects.length === 0 && (
                <tr><td colSpan={6} className="u-empty-state">Nenhum projeto em andamento.</td></tr>
              )}
              {projects.map((p: any) => (
                <tr key={p.id}>
                  <td><b>{p.name || 'Projeto'}</b></td>
                  <td>{p.service_type || 'Servi├ºo'}</td>
                  <td className="u-text-gold">${p.contract_value ? Number(p.contract_value).toLocaleString() : '0'}</td>
                  <td>
                    <div className="prog-bar" style={{ width: '80px' }}>
                      <div className="prog-fill" style={{ width: `${p.progress || 0}%` }}></div>
                    </div>
                    <div style={{ fontSize: '.65rem', color: 'var(--t2)', marginTop: '3px' }}>
                      {p.progress || 0}%
                    </div>
                  </td>
                  <td><span className={`status-b ${p.status === 'active' ? 'sb-active' : ''}`}>{p.status || 'ND'}</span></td>
                  <td>
                    <div style={{ display: 'flex', gap: '12px', justifyContent: 'center', alignItems: 'center' }}>
                      <Button 
                        variant="ghost" 
                        className="rounded-full px-3 py-1 text-[0.75rem]" 
                        onClick={() => {
                          setNewProjectForm({ 
                            name: p.name || '', 
                            service_type: p.service_type || '', 
                            contract_value: String(p.contract_value || ''), 
                            deadline: p.deadline || '', 
                            start_date: (p as any).start_date || '', 
                            client_id: (p as any).client_id || '' 
                          });
                          setEditingProjectId(p.id);
                          setIsNewProjectOpen(true);
                        }}
                      >
                        Ô£Å´©Å Editar
                      </Button>

                      <Button 
                        variant="ghost" 
                        className="px-2 py-1 text-[.7rem] text-danger border-transparent" 
                        onClick={() => {
                          showConfirm(`Deseja excluir o projeto "${p.name}"?`, async () => {
                            try {
                              await deleteProjectMutation.mutateAsync(p.id);
                              showToast('Projeto exclu├¡do com sucesso!');
                            } catch (err: any) {
                              showToast('Erro: ' + err.message);
                            }
                          });
                        }}
                      >
                        ­ƒùæ´©Å
                      </Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </CardContent>
      </Card>
    </div>
  );
}

