            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
              <div>
                <label className="u-mono-label">T├¡tulo *</label>
                <input className="f-inp u-w-full" placeholder="Ex: Vistoria da funda├º├úo" value={newEvent.title} onChange={e => setNewEvent({...newEvent, title: e.target.value})} />
              </div>
              <div>
                <label className="u-mono-label">Projeto (opcional)</label>
                <select className="f-inp u-w-full" value={newEvent.project_id} onChange={e => setNewEvent({...newEvent, project_id: e.target.value})}>
