                <textarea className="f-inp" style={{resize:'vertical',minHeight:70}} placeholder="Anote informa├º├Áes sobre este lead..." value={leadNotes[l.id] !== undefined ? leadNotes[l.id] : (l.notes || '')} onChange={e => setLeadNotes(prev => ({...prev, [l.id]: e.target.value}))}></textarea>
