import { useState } from 'react';
import { supabase } from '../lib/supabase';
import type { CalendarEvent, EditingEvent, GoogleEvent } from '../types';

export function useCalendar() {
  const [calendarEvents, setCalendarEvents] = useState<CalendarEvent[]>([]);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [eventForm, setEventForm] = useState({ lead_id: '', date: '', time: '00:00', title: '' });
  const [editingEvent, setEditingEvent] = useState<EditingEvent | null>(null);
  const [googleEvents, setGoogleEvents] = useState<GoogleEvent[]>([]);
  const [isGoogleLinked, setIsGoogleLinked] = useState(false);

  const fetchCalendarEvents = async () => {
    const { data } = await supabase.from('calendar_events').select('*');
    if (data) setCalendarEvents(data);
    return data;
  };

  const createEvent = async (eventData: any) => {
    const { error } = await supabase.from('calendar_events').insert([eventData]);
    if (!error) await fetchCalendarEvents();
    return { error };
  };

  const updateEvent = async (id: string, updates: any) => {
    const { error } = await supabase.from('calendar_events').update(updates).eq('id', id);
    if (!error) await fetchCalendarEvents();
    return { error };
  };

  const deleteEvent = async (id: string) => {
    const { error } = await supabase.from('calendar_events').delete().eq('id', id);
    if (!error) setCalendarEvents(prev => prev.filter(e => e.id !== id));
    return { error };
  };

  const fetchGoogleEvents = async (token: string) => {
    try {
      const now = new Date();
      const timeMin = new Date(now.getFullYear(), now.getMonth() - 1, 1).toISOString();
      const timeMax = new Date(now.getFullYear(), now.getMonth() + 2, 0).toISOString();
      const res = await fetch(
        `https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${timeMin}&timeMax=${timeMax}&singleEvents=true&orderBy=startTime`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      if (res.ok) {
        const data = await res.json();
        setGoogleEvents(data.items || []);
      }
    } catch (err) {
      console.warn('Google Calendar sync failed:', err);
    }
  };

  return {
    calendarEvents, setCalendarEvents,
    isEventModalOpen, setIsEventModalOpen,
    eventForm, setEventForm,
    editingEvent, setEditingEvent,
    googleEvents, setGoogleEvents,
    isGoogleLinked, setIsGoogleLinked,
    fetchCalendarEvents, createEvent, updateEvent, deleteEvent, fetchGoogleEvents,
  };
}

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import type { Message, ChatPartner } from '../types';

export function useChat() {
  const [selectedChatUser, setSelectedChatUser] = useState<ChatPartner | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [allChatMessages, setAllChatMessages] = useState<Message[]>([]);
  const messagesEndRef = React.useRef<HTMLDivElement>(null);

  // Media & Audio States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const mediaRecorderRef = React.useRef<MediaRecorder | null>(null);
  const audioChunksRef = React.useRef<Blob[]>([]);
  const recordingTimerRef = React.useRef<any>(null);
  const fileInputRef = React.useRef<HTMLInputElement>(null);

  const fetchMessages = async (userId: string, partnerId: string) => {
    const { data } = await supabase
      .from('messages')
      .select('*')
      .or(`and(sender_id.eq.${userId},receiver_id.eq.${partnerId}),and(sender_id.eq.${partnerId},receiver_id.eq.${userId})`)
      .order('created_at', { ascending: true });
    if (data) setMessages(data);
    return data;
  };

  const sendMessage = async (senderId: string, receiverId: string, content: string, type: string = 'text') => {
    const { error } = await supabase.from('messages').insert([{
      sender_id: senderId,
      receiver_id: receiverId,
      content,
      type: type,
    }]);
    return { error };
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return {
    selectedChatUser, setSelectedChatUser,
    messages, setMessages,
    newMessage, setNewMessage,
    allChatMessages, setAllChatMessages,
    messagesEndRef,
    isRecording, setIsRecording,
    recordingTime, setRecordingTime,
    isUploading, setIsUploading,
    mediaRecorderRef, audioChunksRef, recordingTimerRef, fileInputRef,
    fetchMessages, sendMessage, formatTime,
  };
}

import { useState } from 'react';
