      id: ev.id,
      title: ev.title,
      date: startDate ? startDate.toISOString().substring(0, 10) : '',
      time: startDate ? startDate.toTimeString().substring(0, 5) : '00:00',
      is_google_native: ev.extendedProps?.is_google_native || false,
    });
  };

  const handleEditEventSave = async () => {
    if (!editingEvent) return;
    try {
      if (editingEvent.is_google_native) {
        showToast('Eventos do Google n├úo podem ser editados aqui.');
        return;
      }
      const { error } = await supabase.from('calendar_events').update({
        event_date: editingEvent.date,
        start_time: editingEvent.time,
        title: editingEvent.title,
      }).eq('id', editingEvent.id);
      if (error) throw error;
      setCalendarEvents(prev => prev.map(e => e.id === editingEvent.id ? { ...e, event_date: editingEvent.date, start_time: editingEvent.time, title: editingEvent.title } : e));
      showToast('Evento atualizado com sucesso!');
      setEditingEvent(null);
    } catch (err: any) {
      console.error(err);
      showToast('Erro ao atualizar evento.');
    }
  };

  const handleEditEventDelete = async () => {
    if (!editingEvent) return;
    showConfirm(`Deseja excluir o agendamento "${editingEvent.title}"?`, async () => {
      try {
        if (editingEvent.is_google_native) {
          const token = localStorage.getItem('google_provider_token');
          if (!token) {
            showToast("Conecte seu Google Calendar primeiro para excluir este evento.");
            return;
          }
          const resp = await fetch(`https://www.googleapis.com/calendar/v3/calendars/primary/events/${editingEvent.id}`, {
            method: 'DELETE',
            headers: { 'Authorization': `Bearer ${token}` }
          });
          if (!resp.ok) throw new Error("Falha ao excluir no Google");
          setGoogleEvents(prev => prev.filter(e => e.id !== editingEvent.id));
          showToast("Evento exclu├¡do do Google Calendar!");
          setEditingEvent(null);
          return;
        }
        const { error } = await supabase.from('calendar_events').delete().eq('id', editingEvent.id);
        if (error) throw error;
        setCalendarEvents(prev => prev.filter(e => e.id !== editingEvent.id));
        showToast('Evento exclu├¡do!');
        setEditingEvent(null);
      } catch (err: any) {
        console.error(err);
        showToast("Erro ao excluir evento.");
      }
    });
  };

  const mapEventsForCalendar = () => {
    const local = calendarEvents.map(e => {
       const startStr = e.start_time ? `${e.event_date}T${e.start_time}` : e.event_date;
       const endStr = (e.end_time && e.event_date) ? `${e.event_date}T${e.end_time}` : undefined;
       return {
         id: e.id,
         title: e.title,
         start: startStr,
         end: endStr,
         backgroundColor: 'var(--gold)',
         borderColor: 'var(--gold)',
         textColor: '#000',
         extendedProps: {
           lead_id: e.lead_id
         }
       };
    });
    return [...local, ...googleEvents];
  };

  const totalRevenue = projects.reduce((acc, p) => acc + (Number(p.contract_value) || 0), 0);
  const grossRevenue = totalRevenue;
  const toReceive = projects.reduce((acc, p) => {
     const val = Number(p.contract_value) || 0;
     const paid = val * ((p.progress || 0) / 100);
     return acc + (val - paid);
  }, 0);
  const paidToPartners = projects.reduce((acc, p) => {
     const val = Number(p.contract_value) || 0;
     const paid = val * ((p.progress || 0) / 100);
     return acc + (paid * 0.6); 
  }, 0);

  return (
    <div className="admin-body">
      <nav className={`sb ${sidebarOpen ? 'open' : ''}`} role="navigation" aria-label="Menu principal">
        <div className="sb-brand">
          <img src={theme === 'light' ? "/Logo atual Bravo.png" : "/Logo Fundo azul.jpeg"} alt="Bravo Homes Group" className="sb-logo" style={{background: 'transparent'}} />
          <div className="sb-sub">{t('adminDashboard')}</div>
        </div>
        <div className="sb-admin">
          {userProfile?.avatar_url ? (
            <img src={userProfile.avatar_url} alt="Admin" className="av" style={{objectFit: 'cover', width: '36px', height: '36px', borderRadius: '50%', border: '1px solid var(--gold)'}} />
          ) : (
            <div className="av" style={{textTransform:'uppercase'}}>{(userProfile?.full_name || user?.user_metadata?.full_name || 'A').substring(0, 2)}</div>
          )}
          <div style={{minWidth: 0}}>
            <div className="pname" style={{whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', display: 'block'}}>{userProfile?.full_name || user?.user_metadata?.full_name || 'Admin'}</div>
            <div className="prole">{t('administrator')}</div>
          </div>
        </div>
        <div className="sb-nav">
          <div className="sb-sec">{t('overview')}</div>
          <div className={navItemClass('dashboard')} onClick={() => navTo('dashboard')}><span className="ni-icon">Ôùê</span>{t('dashboard')}</div>
          
          <div className="sb-sec">{t('sales')}</div>
          <div className={navItemClass('pipeline')} onClick={() => navTo('pipeline')}><span className="ni-icon">Ôùº</span>{t('pipeline')}{activeLeadsCount > 0 && <span className="badge gold">{activeLeadsCount}</span>}</div>
          <div className={navItemClass('allleads')} onClick={() => navTo('allleads')}><span className="ni-icon">ÔùÄ</span>{t('allLeads')}</div>
          <div className={navItemClass('lp')} onClick={() => navTo('lp')}><span className="ni-icon">Ôè×</span>{t('landingPages')}{landingPages.length > 0 && <span className="badge blue">{landingPages.length}</span>}</div>
          
          <div className="sb-sec">{t('operations')}</div>
          <div className={navItemClass('projects')} onClick={() => navTo('projects')}><span className="ni-icon">Ôûª</span>{t('activeProjects')}{projects.length > 0 && <span className="badge gold">{projects.length}</span>}</div>
          <div className={navItemClass('calendar')} onClick={() => navTo('calendar')}><span className="ni-icon">­ƒôà</span>{t('calendar')}</div>
          <div className={navItemClass('clients')} onClick={() => navTo('clients')}><span className="ni-icon">Ôùë</span>{t('clients')}</div>
          <div className={navItemClass('partners')} onClick={() => navTo('partners')}><span className="ni-icon">­ƒæÀ</span>{t('partners')}</div>
          
          <div className="sb-sec">{t('financial')}</div>
          <div className={navItemClass('finances')} onClick={() => navTo('finances')}><span className="ni-icon">$</span>{t('finances')}</div>
          
          <div className="sb-sec">{t('messaging')}</div>
          <div className={navItemClass('adminchat')} onClick={() => navTo('adminchat')}><span className="ni-icon">­ƒÆ¼</span>{t('chat')}</div>
          <div className={navItemClass('social')} onClick={() => navTo('social')}><span className="ni-icon">­ƒô▒</span>Social Media</div>
          
          <div className="sb-sec">SYSTEM</div>
          <div className={navItemClass('settings')} onClick={() => navTo('settings')}><span className="ni-icon">ÔÜÖ</span>{t('settings')}</div>
        </div>
        <div className="sb-footer">
          <div className="logout" style={{textAlign:'center'}} onClick={async () => { localStorage.removeItem('adminActiveTab'); await supabase.auth.signOut(); window.location.href = '/'; }}>­ƒÜ¬ {t('logout')}</div>
        </div>
      </nav>
      {/* Mobile sidebar backdrop */}
      <div className={`sb-overlay ${sidebarOpen ? 'open' : ''}`} onClick={() => setSidebarOpen(false)} aria-hidden="true"></div>

      <div className="main">
        <div className="topbar">
          <button className="sb-toggle" onClick={() => setSidebarOpen(!sidebarOpen)} aria-label="Abrir/fechar menu lateral">Ôÿ░</button>
          <div className="topbar-title">{{'lp':t('topbarLandingPages'),'allleads':t('topbarAllLeads'),'adminchat':t('topbarChat'),'projects':t('topbarProjects'),'pipeline':t('topbarPipeline'),'calendar':t('topbarCalendar'),'partners':t('topbarPartners'),'clients':t('topbarClients'),'finances':t('topbarFinances'),'settings':t('topbarSettings'),'dashboard':t('topbarDashboard')}[activeTab] || activeTab.toUpperCase()}</div>
          <div className="topbar-actions"></div>
          <button className="notif-btn" onClick={() => setIsNotifOpen(!isNotifOpen)} aria-label="Abrir notifica├º├Áes" style={{position:'relative'}}>
            ­ƒöö
            {unreadCount > 0 && <span style={{position:'absolute',top:'-2px',right:'-2px',background:'var(--red)',color:'#fff',fontSize:'0.55rem',fontWeight:700,borderRadius:'50%',width:16,height:16,display:'flex',alignItems:'center',justifyContent:'center'}}>{unreadCount}</span>}
          </button>
          <button className="theme-btn" onClick={toggleTheme} aria-label={theme === 'dark' ? 'Ativar modo claro' : 'Ativar modo escuro'}>{theme === 'dark' ? '­ƒîÖ' : 'ÔÿÇ´©Å'}</button>
        </div>
        
        {isNotifOpen && (
          <div className="notif-panel open" style={{ right: 30 }}>
            <div className="nphead">Notifica├º├Áes {unreadCount > 0 && <span style={{background:'var(--red)',color:'#fff',fontSize:'0.55rem',borderRadius:10,padding:'1px 6px',marginLeft:6}}>{unreadCount}</span>} <span className="npclear" style={{cursor: 'pointer'}} onClick={() => setNotifications(prev => prev.map(n => ({...n, read: true})))}>Marcar todas lidas</span></div>
            <div style={{maxHeight:'350px',overflowY:'auto'}}>
              {notifications.length === 0 && <div className="empty-state" style={{padding: '20px'}}>Sem notifica├º├Áes</div>}
              {notifications.slice(0, 20).map(n => (
                <div key={n.id} onClick={() => setNotifications(prev => prev.map(x => x.id === n.id ? {...x, read: true} : x))} style={{padding:'10px 16px',borderBottom:'1px solid var(--b)',cursor:'pointer',background: n.read ? 'transparent' : 'rgba(201,148,58,0.08)',transition:'all .2s'}}>
                  <div style={{display:'flex',alignItems:'center',gap:6,marginBottom:2}}>
                    <span style={{fontSize:'0.7rem'}}>{n.type}</span>
                    {!n.read && <span style={{width:6,height:6,borderRadius:'50%',background:'var(--red)',flexShrink:0}}></span>}
                  </div>
                  <div style={{fontSize:'0.8rem',fontWeight: n.read ? 400 : 700,color:'var(--text)'}}>{n.title}</div>
                  <div style={{fontSize:'0.7rem',color:'var(--t3)',marginTop:2}}>{n.body}</div>
                  <div style={{fontSize:'0.6rem',color:'var(--t3)',marginTop:4,fontFamily:"'DM Mono',monospace"}}>{n.time.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}</div>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="content">

          {/* DASHBOARD TAB */}
          {activeTab === 'dashboard' && <AdminOverviewTab setActiveTab={setActiveTab} />}

          {/* PIPELINE TAB */}
          {activeTab === 'pipeline' && (
            <AdminPipelineTab 
              setIsNewLeadOpen={setIsNewLeadOpen}
              setSelectedLead={setSelectedLead}
            />
          )}

          {/* PROJECTS TAB */}
          {activeTab === 'projects' && (
            <AdminProjectsTab
              handleCreateProject={handleCreateProject}
              setNewProjectForm={setNewProjectForm}
              setEditingProjectId={setEditingProjectId}
              setIsNewProjectOpen={setIsNewProjectOpen}
              showConfirm={showConfirm}
            />
          )}

          {/* ALL LEADS TAB */}
          {activeTab === 'allleads' && (
            <AdminAllLeadsTab
              setIsNewLeadOpen={setIsNewLeadOpen}
              setSelectedLead={setSelectedLead}
              showConfirm={showConfirm}
            />
          )}

          {/* LANDING PAGES TAB */}
          {activeTab === 'lp' && (
            <AdminLandingPagesTab
              setIsLPOpen={setIsLPOpen}
              showConfirm={showConfirm}
            />
          )}

          {/* CALENDAR TAB */}
          {activeTab === 'calendar' && (
            <CalendarTab
              handleGoogleSync={handleGoogleSync}
              setEventForm={setEventForm}
              setIsEventModalOpen={setIsEventModalOpen}
              mapEventsForCalendar={mapEventsForCalendar}
              handleEventDrop={handleEventDrop}
              handleEventClick={handleEventClick}
            />
          )}

          {/* PARTNERS TAB */}
          {activeTab === 'partners' && (
            <PartnersTab
              partners={partners}
              projects={projects}
              loadingDb={loadingDb}
              setIsPartnerOpen={setIsPartnerOpen}
              setSelectedPartner={setSelectedPartner}
            />
          )}

          {/* CLIENTS TAB */}
          {activeTab === 'clients' && (
            <ClientsTab
              clients={clients}
              loadingDb={loadingDb}
              setIsNewLeadOpen={setIsNewLeadOpen}
              showToast={showToast}
              handleDeleteClient={handleDeleteClient}
            />
          )}

          {/* SOCIAL MEDIA TAB */}
          {activeTab === 'social' && (
            <SocialMediaTab
              socialAccounts={socialAccounts}
              socialPosts={socialPosts}
              socialPostForm={socialPostForm}
              setSocialPostForm={setSocialPostForm}
              socialPosting={socialPosting}
              handleSocialPublish={handleSocialPublish}
              handleFbConnect={handleFbConnect}
            />
          )}

          {/* FINANCES TAB */}
          {activeTab === 'finances' && (
            <div className="page active">
              <div style={{marginBottom:16}}><div className="u-syne-title">Financeiro</div></div>
              <div className="g3">
                 <div className="kpi"><div className="kl">Faturamento Bruto</div><div className="kv u-text-gold">${grossRevenue.toLocaleString(undefined, {maximumFractionDigits:0})}</div></div>
                 <div className="kpi"><div className="kl">A Receber</div><div className="kv">${toReceive.toLocaleString(undefined, {maximumFractionDigits:0})}</div></div>
                 <div className="kpi"><div className="kl">Pago aos Parceiros</div><div className="kv">${paidToPartners.toLocaleString(undefined, {maximumFractionDigits:0})}</div></div>
              </div>
              <div className="card">
                <div className="ch"><span className="ct">├Ültimos Pagamentos</span></div>
                <div className="cb empty-state">O m├│dulo financeiro est├í sincronizando com sua conta Stripe/Banco.</div>
              </div>
            </div>
          )}

           {/* SETTINGS TAB */}
          {activeTab === 'settings' && (
            <SettingsTab
              t={t} userProfile={userProfile} user={user}
              adminName={adminName} setAdminName={setAdminName}
              adminEmail={adminEmail} setAdminEmail={setAdminEmail}
              adminPhone={adminPhone} setAdminPhone={setAdminPhone}
              handleProfileSave={handleProfileSave}
              handleAvatarUpload={handleAvatarUpload}
              isUploadingAvatar={isUploadingAvatar}
              showToast={showToast} showConfirm={showConfirm}
              notifPrefs={notifPrefs} toggleNotifPref={toggleNotifPref}
              lang={lang} setLang={setLang}
            />
          )}

          {/* ADMINCHAT TAB */}
          {activeTab === 'adminchat' && (
            <ChatPanel
              chatPartners={chatPartners}
              selectedChatUser={selectedChatUser}
              setSelectedChatUser={setSelectedChatUser}
              messages={messages}
              setMessages={setMessages}
              setAllChatMessages={setAllChatMessages}
              user={user}
              newMessage={newMessage}
              setNewMessage={setNewMessage}
              handleSendMessage={handleSendMessage}
              renderMessageContent={renderMessageContent}
              messagesEndRef={messagesEndRef}
              showToast={showToast}
              showConfirm={showConfirm}
              isRecording={isRecording}
              recordingTime={recordingTime}
              formatTime={formatTime}
              cancelRecording={cancelRecording}
              stopRecordingAndSend={stopRecordingAndSend}
              startRecording={startRecording}
              isUploading={isUploading}
              handleFileSelect={handleFileSelect}
              fileInputRef={fileInputRef}
              supabase={supabase}
            />
          )}

        </div>
      </div>

      {/* LEAD DETALHES MODAL */}
      <div className={`modal-overlay ${selectedLead ? 'open' : ''}`} onClick={() => setSelectedLead(null)}>
        {selectedLead && (
          <div className="modal" onClick={e => e.stopPropagation()}>
            <div className="modal-head" style={{alignItems: 'flex-start', paddingTop: '20px'}}>
              <div style={{width: '100%', marginRight: '30px'}}>
                <div style={{fontSize: '0.65rem', color: 'var(--t3)', textTransform: 'uppercase', letterSpacing: '1px', marginBottom: '4px'}}>Nome Completo</div>
                <input 
                  type="text"
                  className="modal-title"
                  style={{background: 'transparent', border: 'none', color: 'inherit', font: 'inherit', outline: 'none', borderBottom: '1px dashed var(--t3)', width: '100%', textOverflow: 'ellipsis', paddingBottom: '4px', margin: 0}}
                  value={selectedLead.name ?? selectedLead.clients?.name ?? ''}
                  onChange={e => setSelectedLead({...selectedLead, name: e.target.value})}
                  onBlur={async () => {
                     if (selectedLead.name !== undefined) {
                        await updateLead(selectedLead.id, { name: selectedLead.name });
                     }
                  }}
                  placeholder="Nome do Lead / Cliente"
                  title="Clique para editar o nome"
                />
              </div>
              <button className="dclose" aria-label="Fechar" style={{marginTop: '-8px'}} onClick={() => setSelectedLead(null)}>Ô£ò</button>
            </div>
            <div className="modal-body" style={{display: 'flex', gap: '20px'}}>
              <div className="u-flex-1">
                <div className="d-row">
                  <div className="dfield"><div className="dlabel">Servi├ºo</div><div className="dval">{selectedLead.service_type || 'N/D'}</div></div>
                  <div className="dfield"><div className="dlabel">Local</div><div className="dval">{selectedLead.city || 'N/D'}</div></div>
                  <div className="dfield">
                    <div className="dlabel">Valor Est.</div>
                    <div style={{display: 'flex', alignItems: 'center', gap: '4px'}}>
                      <span className="dval big u-text-gold">$</span>
                      <input 
                        type="number"
                        className="dval big" 
                        title="Clique para editar o valor"
                        style={{color: 'var(--gold)', background: 'transparent', border: 'none', borderBottom: '1px dashed var(--t3)', width: '100px', outline: 'none', padding: 0}}
                        value={selectedLead.estimated_value || ''}
                        onChange={e => setSelectedLead({...selectedLead, estimated_value: e.target.value ? parseFloat(e.target.value) : undefined})}
                        onBlur={async () => {
                           const val = parseFloat(String(selectedLead.estimated_value ?? ''));
                           if (!isNaN(val)) await updateLead(selectedLead.id, { estimated_value: val });
                        }}
                        placeholder="N/D"
                      />
                    </div>
                  </div>
                </div>
                
                <div style={{marginTop: '20px'}}>
                  <div className="dlabel">A├º├Áes / Mudar Fase</div>
                  <div style={{display: 'flex', gap: '8px', flexWrap: 'wrap', marginTop: '6px'}}>
                    <select className="f-inp" style={{width: 'auto'}} value={selectedLead.status} onChange={(e) => updateLead(selectedLead.id, {status: e.target.value})}>
                      <option value="new">Nova / Recebida</option>
                      <option value="contacted">Em Contato</option>
                      <option value="scheduling">Agendamento de Vistoria</option>
                      <option value="proposal">Proposta Enviada</option>
                      <option value="closed">Fechado Ô£ô</option>
                    </select>

                    <button className="btn ghost" style={selectedLead.urgency === 'hot' ? {background:'rgba(201,148,58,0.15)',borderColor:'var(--gold)'} : {}} onClick={() => updateLead(selectedLead.id, {urgency: 'hot'})}>­ƒöÑ Quente</button>
                    <button className="btn ghost" style={selectedLead.urgency === 'warm' ? {background:'rgba(201,148,58,0.15)',borderColor:'var(--gold)'} : {}} onClick={() => updateLead(selectedLead.id, {urgency: 'warm'})}>ÔÿÇ´©Å Morno</button>
                    <button className="btn ghost" style={selectedLead.urgency === 'cool' ? {background:'rgba(201,148,58,0.15)',borderColor:'var(--gold)'} : {}} onClick={() => updateLead(selectedLead.id, {urgency: 'cool'})}>ÔØä´©Å Frio</button>
                  </div>
                </div>

                <div style={{marginTop: '20px', background: 'var(--bg3)', padding: '12px', borderRadius: '8px', fontSize: '0.8rem'}}>
                  <label className="dlabel">Hist├│rico / Notas Internas</label>
                  
                  <div style={{display:'flex',gap:'8px', alignItems:'flex-start', marginBottom:'12px'}}>
                    <textarea className="f-inp" placeholder="Adicionar nova nota..." value={notesInput} onChange={e => setNotesInput(e.target.value)} onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleNotesSave(); } }} style={{resize: 'vertical', minHeight: '44px', paddingTop: '10px'}} />
                    <button className="btn gold" onClick={handleNotesSave} style={{alignSelf: 'stretch', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 16px'}}>Gravar</button>
                  </div>

                  <div style={{maxHeight: '200px', overflowY: 'auto', paddingRight: '4px'}}>
                    {localNotes.length === 0 ? (
                      <div style={{color:'var(--t3)', fontStyle:'italic', fontSize:'0.75rem'}}>Nenhum hist├│rico registrado.</div>
                    ) : (
                      localNotes.map((note, idx) => (
                        <div key={note.id} style={{marginBottom: '6px', background: 'var(--bg2)', padding: '8px 10px', borderRadius: '6px', border: '1px solid var(--b)', position:'relative'}}>
                          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'2px'}}>
                            {note.date && <div style={{fontSize: '0.6rem', color: 'var(--gold)', fontWeight:700}}>{note.date}</div>}
                            <button title="Excluir nota" onClick={() => {
                              const newNotes = localNotes.filter((_: any, i: number) => i !== idx);
                              setLocalNotes(newNotes);
                              saveLocalNotes(newNotes);
                            }} style={{background:'none',border:'none',cursor:'pointer',color:'var(--t3)',fontSize:'0.7rem',padding:'0 2px',lineHeight:1,opacity:0.6,transition:'opacity .2s'}}
                              onMouseEnter={e => (e.currentTarget.style.opacity = '1')}
                              onMouseLeave={e => (e.currentTarget.style.opacity = '0.6')}
                            >­ƒùæ´©Å</button>
                          </div>
                          <textarea 
                            className="f-inp"
                            style={{minHeight: '28px', height: 'auto', resize: 'none', width: '100%', background: 'transparent', border: 'none', padding: 0, color: 'var(--text)', outline: 'none', fontSize: '0.75rem'}}
                            value={note.text}
                            onChange={(e) => {
                              const newNotes = [...localNotes];
                              newNotes[idx].text = e.target.value;
                              setLocalNotes(newNotes);
                            }}
                            onBlur={() => saveLocalNotes(localNotes)}
                          />
                        </div>
                      ))
                    )}
                  </div>
                </div>
              </div>

              <div style={{width: '220px', flexShrink: 0, paddingLeft: '16px', borderLeft: '1px solid var(--b)'}}>
                {partners.length > 0 && (<>
                <div className="dlabel">Atribuir a Parceiro(s)</div>
                <div style={{marginTop:'6px', marginBottom:'12px'}}>
                    {partners.map((p: any) => {
                      const assignedList: string[] = selectedLead.assigned_partners || [];
                      const isAssigned = assignedList.includes(p.id);
                      return (
                        <div key={p.id} style={{display:'flex',alignItems:'center',gap:'8px',padding:'6px 8px',borderRadius:'6px',marginBottom:'4px',cursor:'pointer',background: isAssigned ? 'rgba(201,148,58,0.15)' : 'transparent',border: isAssigned ? '1px solid var(--gold)' : '1px solid var(--b)',transition:'all .2s'}}
                          onClick={async () => {
                            const newList = isAssigned ? assignedList.filter((id: string) => id !== p.id) : [...assignedList, p.id];
                            setSelectedLead({...selectedLead, assigned_partners: newList});
                            await updateLead(selectedLead.id, { assigned_partners: newList });

                            // Notify the partner when assigned
                            if (!isAssigned) {
                              const leadName = selectedLead.clients?.name || selectedLead.name || 'Novo Lead';
                              await supabase.from('notifications').insert({
                                user_id: p.id,
                                title: '­ƒÄ» Novo Lead atribu├¡do a voc├¬!',
                                body: `${leadName} ÔÇö ${selectedLead.service_type || ''} ÔÇö ${selectedLead.city || ''} ÔÇö $${(selectedLead as any).estimated_value || '?'}`,
                                type: 'lead_assigned',
                                link: '/partner'
                              });
                            }

                            // When assigning a partner: create Client if not yet created
                            if (!isAssigned && !selectedLead.client_id) {
                              const { data: newClient } = await supabase.from('clients').insert({
                                name: selectedLead.clients?.name || selectedLead.name || 'Unknown',
                                email: (selectedLead as any).email || '',
                                phone: (selectedLead as any).phone || '',
                                city: selectedLead.city || '',
                                state: 'GA'
                              }).select().single();
                              if (newClient) {
                                await updateLead(selectedLead.id, { client_id: newClient.id });
                                setSelectedLead({...selectedLead, assigned_partners: newList, client_id: newClient.id, clients: newClient});
                                setClients(prev => [...prev, newClient]);
                                showToast('Lead promovido a Cliente!');
                              }
                            }
                          }}
                        >
                          <div style={{width:14,height:14,borderRadius:3,border: isAssigned ? '2px solid var(--gold)' : '2px solid var(--b2)',background: isAssigned ? 'var(--gold)' : 'transparent',display:'flex',alignItems:'center',justifyContent:'center',fontSize:'0.6rem',color:'#000',flexShrink:0}}>
                            {isAssigned && 'Ô£ô'}
                          </div>
                          <div style={{fontSize:'0.78rem',fontWeight: isAssigned ? 600 : 400,color: isAssigned ? 'var(--gold)' : 'var(--text)'}}>­ƒæÀ {p.full_name || p.name || 'Parceiro'}</div>
                        </div>
                      );
                    })}
                </div>
                </>)}
                
                <div className="dlabel" style={{marginTop: '20px'}}>Outras A├º├Áes</div>
                    <button className="btn ghost" style={{width: '100%', marginBottom: '10px', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '6px'}} onClick={() => {
                        const leadName = selectedLead.clients?.name || selectedLead.name || 'Desconhecido';
                        setEventForm({ lead_id: selectedLead.id, date: '', time: '00:00', title: `Vistoria: ${leadName}` });
                        setIsEventModalOpen(true);
                    }}>
                      ­ƒùô´©Å Agendar Vistoria
                    </button>
                    <button className="btn" style={{background: 'transparent', border: '1px solid rgba(231,76,60,0.3)', color: 'var(--red)', width: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center'}} onClick={() => {
                      showConfirm('Certeza que deseja descartar este lead?', () => {
                        updateLead(selectedLead.id, { status: 'lost' });
                        setSelectedLead(null);
                      });
                    }}>
                      Descartar Lead
                    </button>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* EVENT MODAL */}
      <EventModal
        isOpen={isEventModalOpen}
        onClose={() => setIsEventModalOpen(false)}
        onSubmit={handleEventSubmit}
        eventForm={eventForm}
        setEventForm={setEventForm}
        leads={leads}
        selectedLead={selectedLead}
      />

      {/* EDIT EVENT MODAL */}
      {editingEvent && (
        <div className="modal-overlay open" onClick={() => setEditingEvent(null)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{maxWidth: '420px'}}>
            <div className="modal-head">
              <div className="modal-title">Editar Agendamento</div>
              <span className="modal-close" onClick={() => setEditingEvent(null)}>├ù</span>
            </div>
            <div className="modal-body">
              <div style={{marginBottom:'12px'}}>
                <label className="f-label">T├¡tulo</label>
                <input type="text" className="f-inp" value={editingEvent.title} onChange={e => setEditingEvent({...editingEvent, title: e.target.value})} />
              </div>
              <div className="f-row">
                <div>
                  <label className="f-label">Data *</label>
                  <input required type="date" className="f-inp" value={editingEvent.date} onChange={e => setEditingEvent({...editingEvent, date: e.target.value})} onClick={(e) => { try { 'showPicker' in e.target && (e.target as HTMLInputElement).showPicker() } catch(err){} }} />
                </div>
                <div>
                  <label className="f-label">Hor├írio *</label>
                  <input required type="time" className="f-inp" value={editingEvent.time} onChange={e => setEditingEvent({...editingEvent, time: e.target.value})} onClick={(e) => { try { 'showPicker' in e.target && (e.target as HTMLInputElement).showPicker() } catch(err){} }} />
                </div>
              </div>
            </div>
            <div className="modal-foot" style={{justifyContent:'space-between'}}>
              <button type="button" className="btn" style={{background:'transparent',border:'1px solid rgba(231,76,60,0.5)',color:'var(--red)'}} onClick={handleEditEventDelete}>­ƒùæ´©Å Excluir</button>
              <div style={{display:'flex',gap:'8px'}}>
                <button type="button" className="btn ghost" onClick={() => setEditingEvent(null)}>Cancelar</button>
                <button type="button" className="btn gold" onClick={handleEditEventSave}>Salvar Altera├º├Áes</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* LP MODAL */}
      {isLPOpen && (
        <div className="modal-overlay open" onClick={() => setIsLPOpen(false)}>
          <div className="modal u-modal-md" onClick={e => e.stopPropagation()}>
            <div className="modal-head">
              <div className="modal-title">Nova Landing Page</div>
              <button className="dclose" aria-label="Fechar" onClick={() => setIsLPOpen(false)}>Ô£ò</button>
            </div>
            <form onSubmit={handleLPSubmit}>
              <div className="modal-body">
                <div className="f-row">
                  <div className="u-w-full">
                    <label className="f-label">Servi├ºo / Nome da P├ígina *</label>
                    <input required type="text" className="f-inp" placeholder="Ex: Kitchen Remodel" value={lpForm.name} onChange={e => setLpForm({...lpForm, name: e.target.value})} />
                  </div>
                </div>
                <div className="f-row">
                  <div className="u-w-full">
                    <label className="f-label">Cidade / Regi├úo Alvo *</label>
                    <input required type="text" className="f-inp" placeholder="Ex: Alpharetta" value={lpForm.city} onChange={e => setLpForm({...lpForm, city: e.target.value})} />
                  </div>
                </div>
              </div>
              <div className="modal-foot">
                <button type="button" className="btn ghost" onClick={() => setIsLPOpen(false)}>Cancelar</button>
                <button type="submit" className="btn gold">Criar P├ígina</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* PARTNER MODAL */}
      <PartnerModal
        isOpen={isPartnerOpen}
        onClose={() => setIsPartnerOpen(false)}
        onSubmit={handlePartnerSubmit}
        form={partnerForm}
        setForm={setPartnerForm}
      />

      {/* PARTNER DETALHES MODAL - EDITABLE */}
      <div className={`modal-overlay ${selectedPartner ? 'open' : ''}`} onClick={() => { setSelectedPartner(null); setEditPartner(null); }}>
        {selectedPartner && (
          <div className="modal" onClick={e => e.stopPropagation()} style={{maxWidth: '520px'}}>
            <div className="modal-head">
              <div className="modal-title">Perfil do Parceiro</div>
              <button className="dclose" aria-label="Fechar" onClick={() => { setSelectedPartner(null); setEditPartner(null); }}>Ô£ò</button>
            </div>
            <div className="modal-body">
              <div style={{display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '20px'}}>
                <div style={{width: '60px', height: '60px', borderRadius: '50%', background: 'var(--gold)', color: '#000', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.5rem', fontWeight: 'bold'}}>
                  {(selectedPartner.name || selectedPartner.full_name || 'PA').substring(0,2).toUpperCase()}
                </div>
                <div className="u-flex-1">
                  <h2 style={{margin: 0, fontSize: '1.2rem', color: 'var(--gold)'}}>{selectedPartner.name || selectedPartner.full_name || 'Sem nome'}</h2>
                  <div style={{color: 'var(--t2)', fontSize: '0.9rem'}}>{selectedPartner.specialty || 'Empreiteiro Geral'}</div>
                </div>
                {!editPartner && <button className="btn ghost" style={{fontSize:'0.75rem',padding:'6px 12px'}} onClick={() => setEditPartner({...selectedPartner})}>Ô£Å´©Å Editar</button>}
              </div>
              
              {editPartner ? (
                <div style={{display:'flex',flexDirection:'column',gap:'14px'}}>
                  <div className="f-row u-flex-gap-10">
                    <div className="u-flex-1">
                      <label className="f-label">Nome *</label>
                      <input className="f-inp" value={editPartner.full_name || ''} onChange={e => setEditPartner({...editPartner, full_name: e.target.value})} />
                    </div>
                  </div>
                  <div className="f-row u-flex-gap-10">
                    <div className="u-flex-1">
                      <label className="f-label">Telefone</label>
                      <input className="f-inp" placeholder="(000) 000-0000" value={editPartner.phone || ''} onChange={e => setEditPartner({...editPartner, phone: e.target.value})} />
                    </div>
                    <div className="u-flex-1">
                      <label className="f-label">Atua├º├úo (Cidade)</label>
                      <input className="f-inp" placeholder="Ex: Marietta, GA" value={editPartner.city || ''} onChange={e => setEditPartner({...editPartner, city: e.target.value})} />
                    </div>
                  </div>
                  <div className="f-row u-flex-gap-10">
                    <div className="u-flex-1">
                      <label className="f-label">Especialidade</label>
                      <input className="f-inp" placeholder="Ex: Piso, El├®trica" value={editPartner.specialty || ''} onChange={e => setEditPartner({...editPartner, specialty: e.target.value})} />
                    </div>
                    <div className="u-flex-1">
                      <label className="f-label">Status</label>
                      <select className="f-inp" value={editPartner.state || 'available'} onChange={e => setEditPartner({...editPartner, state: e.target.value})}>
                        <option value="available">Dispon├¡vel</option>
                        <option value="busy">Em Projeto</option>
                        <option value="inactive">Inativo</option>
                      </select>
                    </div>
                  </div>
                </div>
              ) : (
                <>
                  <div className="d-row">
                    <div className="dfield"><div className="dlabel">Telefone</div><div className="dval">{selectedPartner.phone || 'N/D'}</div></div>
                    <div className="dfield"><div className="dlabel">Atua├º├úo</div><div className="dval">{selectedPartner.city || 'Georgia'}</div></div>
                  </div>
                  <div className="d-row" style={{marginTop:'10px'}}>
                    <div className="dfield"><div className="dlabel">Especialidade</div><div className="dval">{selectedPartner.specialty || 'Empreiteiro Geral'}</div></div>
                    <div className="dfield"><div className="dlabel">Status</div><div className="dval">{{
                      available: 'Dispon├¡vel', busy: 'Em Projeto', inactive: 'Inativo'
                    }[selectedPartner.state as string] || 'Dispon├¡vel'}</div></div>
                  </div>
                </>
              )}
              
              <div className="dlabel" style={{marginTop: '20px', marginBottom: '10px'}}>Projetos Atribu├¡dos</div>
              {projects.filter(p => p.partner_id === selectedPartner.id).length > 0 ? (
                 <ul style={{listStyle: 'none', padding: 0, margin: 0}}>
                   {projects.filter(p => p.partner_id === selectedPartner.id).map(p => (
                     <li key={p.id} style={{padding: '10px', background: 'var(--bg3)', borderRadius: '6px', marginBottom: '8px', fontSize: '0.85rem'}}>
                        <b>{p.name}</b> ÔÇó {p.status}
                     </li>
                   ))}
                 </ul>
              ) : (
                 <div style={{color: 'var(--t3)', fontSize: '0.85rem', fontStyle: 'italic'}}>Nenhum projeto associado no momento.</div>
              )}
            </div>
            <div className="modal-foot">
              <button className="btn" style={{background: 'transparent', border: '1px solid rgba(231,76,60,0.3)', color: 'var(--red)'}} onClick={() => {
                 showConfirm('Excluir este parceiro?', async () => {
                    await supabase.from('profiles').delete().eq('id', selectedPartner.id);
                    setPartners(prev => prev.filter(p => p.id !== selectedPartner.id));
                    setSelectedPartner(null);
                    setEditPartner(null);
                 });
              }}>Remover Parceiro</button>
              {editPartner ? (
                <div style={{display:'flex',gap:'8px',marginLeft:'auto'}}>
                  <button className="btn ghost" onClick={() => setEditPartner(null)}>Cancelar</button>
                  <button className="btn gold" onClick={async () => {
                    const { error } = await supabase.from('profiles').update({
                      full_name: editPartner.full_name || editPartner.name,
                      phone: editPartner.phone || null,
                      city: editPartner.city || null,
                      specialty: editPartner.specialty || null,
                      state: editPartner.state || 'available'
                    }).eq('id', selectedPartner.id);
                    if (error) { showToast('Erro: ' + error.message); return; }
                    const updated = {...selectedPartner, ...editPartner};
                    setPartners(prev => prev.map(p => p.id === selectedPartner.id ? updated : p));
                    setSelectedPartner(updated);
                    setEditPartner(null);
                    showToast('Parceiro atualizado!');
                  }}>Salvar</button>
                </div>
              ) : (
                <button className="btn ghost" style={{marginLeft:'auto'}} onClick={() => { setSelectedPartner(null); setEditPartner(null); }}>Fechar</button>
              )}
            </div>
          </div>
        )}
      </div>

      {/* NEW LEAD MODAL */}
      <NewLeadModal
        isOpen={isNewLeadOpen}
        onClose={() => setIsNewLeadOpen(false)}
        onSubmit={handleNewLeadSubmit}
        form={newLeadForm}
        setForm={setNewLeadForm}
        partners={partners}
      />

      {/* CONFIRM MODAL */}
      <ConfirmModal
        show={confirmModal.show}
        msg={confirmModal.msg}
        onConfirm={confirmModal.onConfirm}
        onCancel={() => setConfirmModal(prev => ({ ...prev, show: false }))}
      />

      {/* TOAST CONTAINER ÔÇö auto-dismissing, non-blocking */}
      <ToastContainer toasts={toasts} onDismiss={dismissToast} />

      <NewProjectModal
        isOpen={isNewProjectOpen}
        onClose={() => setIsNewProjectOpen(false)}
        onSubmit={submitProjectForm}
        form={newProjectForm}
        setForm={setNewProjectForm}
        editingProjectId={editingProjectId}
        clients={clients}
        projectClientMode={projectClientMode}
        setProjectClientMode={setProjectClientMode}
        newClientName={newClientName}
        setNewClientName={setNewClientName}
      />

    </div>
  );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import { useLanguage } from '../lib/i18n';
import './Login.css';

export default function Login() {
  const navigate = useNavigate();
  const [activeView, setActiveView] = useState<'profile' | 'login' | 'register'>('login');
  const [selectedRole, setSelectedRole] = useState<'admin' | 'parceiro' | 'cliente' | null>('admin');
  const [showPassword, setShowPassword] = useState(false);
  const [showRegPassword, setShowRegPassword] = useState(false);
  const { t } = useLanguage();

  const [theme] = useState(() => localStorage.getItem('appTheme') || 'dark');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [regName, setRegName] = useState('');
  const [regEmail, setRegEmail] = useState('');
  const [regPassword, setRegPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [authError, setAuthError] = useState<string | null>(null);
  const [showEmailPopup, setShowEmailPopup] = useState(false);

  const handleProfileSelect = (role: 'admin' | 'parceiro') => {
    setSelectedRole(role);
    setActiveView('login');
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setAuthError(null);

    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    if (error) {
      setLoading(false);
      setAuthError(error.message);
      return;
    }

    // Fetch role from profiles table
    const { data: profile } = await supabase
      .from('profiles')
      .select('role')
      .eq('id', data.user.id)
      .single();

    setLoading(false);

    const role = profile?.role || 'cliente';
    if (role === 'admin') navigate('/admin');
    else if (role === 'parceiro') navigate('/partner');
    else navigate('/client');
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setAuthError(null);

    const { data, error } = await supabase.auth.signUp({
      email: regEmail,
      password: regPassword,
      options: {
        data: {
          full_name: regName,
        }
      }
    });

    setLoading(false);

    if (error) {
      setAuthError(error.message);
    } else {
      setShowEmailPopup(true);
    }
  };



  return (
    <div className="login-body">
      <div className="login-container">
        <div className="logo-wrapper">
          {/* We import the image from public folder later or replace with absolute path for now */}
          <img src={theme === 'light' ? '/Logo atual Bravo.png' : '/Logo Fundo azul.jpeg'} alt="Bravo Homes Group" className="logo-img" style={{background: 'transparent'}} />
          <div className="logo-subtext">Plataforma de Gest├úo</div>
        </div>

        <div className="view-container">
          {/* PROFILE SELECTION */}
          <div className={`view ${activeView === 'profile' ? 'active' : 'exit-left'}`}>
            <h2 className="profile-title">Selecione seu acesso</h2>
            <div className="profile-cards">
              <div className="profile-card" onClick={() => handleProfileSelect('parceiro')}>
                <div className="pc-icon">­ƒæÀ</div>
                <div className="pc-info">
                  <h3>Sou Parceiro</h3>
                  <p>Acesse suas obras, clientes, fotos e cronograma.</p>
                </div>
                <div className="pc-arrow">Ô×ö</div>
              </div>
              <div className="profile-card" onClick={() => handleProfileSelect('admin')}>
                <div className="pc-icon">­ƒÆ╝</div>
                <div className="pc-info">
                  <h3>Sou Admin</h3>
                  <p>Gerencie leads, equipes, propostas e financeiro.</p>
                </div>
                <div className="pc-arrow">Ô×ö</div>
              </div>
            </div>
          </div>

          {/* LOGIN FORM */}
          <div className={`view ${activeView === 'login' ? 'active' : 'exit-left'}`} style={{ display: activeView === 'login' || activeView === 'register' ? 'block' : 'none' }}>
            <div className="login-card">

              <div className="form-header">
                <h2>{t('loginTitle')}</h2>
                <p>{t('loginSubtitle')}</p>
              </div>

              <form onSubmit={handleLogin}>
                {authError && <div style={{color: 'var(--red)', fontSize: '0.8rem', marginBottom: '10px'}}>{authError}</div>}
                <div className="form-group">
                  <label>{t('email')}</label>
                  <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="form-control" placeholder={t('emailPlaceholder')} required />
                </div>

                <div className="form-group">
                  <label>{t('password')}</label>
                  <div className="pass-wrapper">
                    <input type={showPassword ? 'text' : 'password'} value={password} onChange={(e) => setPassword(e.target.value)} className="form-control" placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó" required />
                    <button type="button" className="pass-toggle" onClick={() => setShowPassword(!showPassword)}>
                      {showPassword ? '­ƒÖê' : '­ƒæü'}
                    </button>
                  </div>
                </div>

                <div className="form-actions">
                  <label className="remember-me">
                    <input type="checkbox" /> {t('rememberMe')}
                  </label>
                  <button type="button" className="forgot-pass" onClick={() => alert(t('forgotSoon'))}>{t('forgotPassword')}</button>
                </div>

                <button type="submit" className="btn-submit" disabled={loading}>
                  <span>{loading ? t('loggingIn') : t('loginButton')}</span>
                </button>
              </form>

              <div className="create-account-row">
                {t('noAccount')} <button type="button" onClick={() => setActiveView('register')}>{t('createAccount')}</button>
              </div>
            </div>
          </div>


          {/* REGISTER FORM */}
          <div className={`view ${activeView === 'register' ? 'active' : 'exit-left'}`} style={{ display: activeView === 'register' ? 'block' : 'none' }}>
            <div className="login-card">
              <button type="button" className="back-btn" onClick={() => setActiveView('login')}>
                ÔåÉ <span>{t('backToLogin')}</span>
              </button>

              <div className="form-header">
                <h2>{t('createAccountTitle')}</h2>
                <p>{t('createAccountSubtitle')}</p>
              </div>

              <form onSubmit={handleRegister}>
                {authError && <div style={{color: 'var(--red)', fontSize: '0.8rem', marginBottom: '10px'}}>{authError}</div>}
                <div className="form-group">
                  <label>{t('fullNameLabel')}</label>
                  <input type="text" value={regName} onChange={(e) => setRegName(e.target.value)} className="form-control" placeholder={t('fullNameLabel')} required />
                </div>
                <div className="form-group">
                  <label>{t('email')}</label>
                  <input type="email" value={regEmail} onChange={(e) => setRegEmail(e.target.value)} className="form-control" placeholder={t('emailPlaceholder')} required />
                </div>
                <div className="form-group">
                  <label>{t('password')}</label>
                  <div className="pass-wrapper">
                    <input type={showRegPassword ? 'text' : 'password'} value={regPassword} onChange={(e) => setRegPassword(e.target.value)} className="form-control" placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó" required />
                    <button type="button" className="pass-toggle" onClick={() => setShowRegPassword(!showRegPassword)}>
                      {showRegPassword ? '­ƒÖê' : '­ƒæü'}
                    </button>
                  </div>
                </div>
                <div className="form-group">
                  <label>{t('profileLabel')}</label>
                  <select className="form-control" required style={{ cursor: 'pointer' }}>
                    <option value="">{t('selectProfile')}</option>
                    <option value="parceiro">{t('partnerContractor')}</option>
                    <option value="cliente">{t('client')}</option>
                  </select>
                </div>

                <button type="submit" className="btn-submit" disabled={loading}>
                  <span>{loading ? t('creatingAccount') : t('createAccountTitle')}</span>
                </button>
              </form>

              <div className="create-account-row" style={{ marginTop: 14 }}>
                {t('alreadyHaveAccount')} <button type="button" onClick={() => setActiveView('login')}>{t('enter')}</button>
              </div>
            </div>
          </div>

        </div>

        <div className="login-footer">
          Bravo Homes Group ┬® 2026<br/><span>Atlanta, Georgia</span>
        </div>
      </div>

      {/* EMAIL CONFIRMATION POPUP */}
      {showEmailPopup && (
        <div style={{position:'fixed',top:0,left:0,right:0,bottom:0,background:'rgba(0,0,0,0.7)',backdropFilter:'blur(6px)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:9999}}>
          <div style={{background:'linear-gradient(145deg,#161920,#1a1e28)',border:'1px solid rgba(184,150,80,0.2)',borderRadius:'16px',maxWidth:'420px',width:'90%',padding:'40px 32px',textAlign:'center',boxShadow:'0 20px 60px rgba(0,0,0,0.5)'}}>
            <div style={{width:'64px',height:'64px',borderRadius:'50%',background:'linear-gradient(135deg,rgba(184,150,80,0.2),rgba(184,150,80,0.05))',border:'2px solid rgba(184,150,80,0.3)',margin:'0 auto 20px',lineHeight:'64px',fontSize:'28px'}}>­ƒôº</div>
            <h2 style={{margin:'0 0 12px',fontSize:'1.3rem',fontWeight:700,color:'#fff'}}>Verifique seu E-mail</h2>
            <p style={{margin:'0 0 8px',fontSize:'0.95rem',lineHeight:1.6,color:'#a0a8b8'}}>
              Enviamos um e-mail de confirma├º├úo para:
            </p>
            <p style={{margin:'0 0 16px',fontSize:'1rem',fontWeight:700,color:'#b89650',wordBreak:'break-all'}}>
              {regEmail}
            </p>
            <p style={{margin:'0 0 24px',fontSize:'0.85rem',lineHeight:1.6,color:'#7a8299'}}>
              Acesse sua caixa de entrada e clique no bot├úo <strong style={{color:'#b89650'}}>"Confirmar meu E-mail"</strong> para ativar sua conta. S├│ depois voc├¬ conseguir├í fazer login.
            </p>
            <button onClick={() => { setShowEmailPopup(false); setActiveView('login'); setEmail(regEmail); }} style={{background:'linear-gradient(135deg,#b89650,#a07d3a)',color:'#fff',border:'none',borderRadius:'8px',padding:'12px 40px',fontSize:'0.95rem',fontWeight:700,cursor:'pointer',boxShadow:'0 4px 15px rgba(184,150,80,0.3)',transition:'transform 0.15s'}}>
              Entendi, vou verificar!
            </button>
            <p style={{margin:'16px 0 0',fontSize:'0.7rem',color:'#4a4f60'}}>
              N├úo recebeu? Verifique a pasta de spam.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../lib/supabase';
import type { Project, Lead, Stage, CalendarEvent, Message, Client, DailyLog, ProjectDocument, EditingEvent, NewEventForm, LogForm, NewProjectForm } from '../types';
import type { User } from '@supabase/supabase-js';
import { useLanguage } from '../lib/i18n';
import type { Lang } from '../lib/i18n';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
import PartnerStagesTab from '../components/partner/PartnerStagesTab';
import PartnerUploadsTab from '../components/partner/PartnerUploadsTab';
import PartnerProfileTab from '../components/partner/PartnerProfileTab';
import PartnerSidebar from '../components/partner/PartnerSidebar';
import PartnerHeader from '../components/partner/PartnerHeader';
import PartnerHomeTab from '../components/partner/PartnerHomeTab';
import PartnerProjectsTab from '../components/partner/PartnerProjectsTab';
import PartnerDailyLogTab from '../components/partner/PartnerDailyLogTab';
import PartnerCalendarTab from '../components/partner/PartnerCalendarTab';
import PartnerLeadsTab from '../components/partner/PartnerLeadsTab';
import PartnerChatTab from '../components/partner/PartnerChatTab';
import '../styles/utilities.css';

export default function PartnerDashboard() {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState(() => localStorage.getItem('partnerActiveTab') || 'dashboard');
  
  useEffect(() => {
    localStorage.setItem('partnerActiveTab', activeTab);
  }, [activeTab]);

  const [theme, setTheme] = useState(() => localStorage.getItem('appTheme') || 'dark');
  const [projects, setProjects] = useState<Project[]>([]);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [stages, setStages] = useState<Stage[]>([]);
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [messages, setMessages] = useState<Message[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [loadingDb, setLoadingDb] = useState(true);
  const [user, setUser] = useState<User | null>(null);
  const [adminUser, setAdminUser] = useState<User | null>(null);
  const [chatTab, setChatTab] = useState<string>('admin');
  const [clients, setClients] = useState<Client[]>([]);
  const [selectedChatClient, setSelectedChatClient] = useState<Client | null>(null);
  const [deleteConfirmClient, setDeleteConfirmClient] = useState<Client | null>(null);
  const [isNewProjectOpen, setIsNewProjectOpen] = useState(false);
  const [isSubmittingProject, setIsSubmittingProject] = useState(false);
  const [toastMessage, setToastMessage] = useState<{title: string, msg: string, type: 'error' | 'success'} | null>(null);
  const [newProjectForm, setNewProjectForm] = useState({ name: '', service_type: 'Reforma', contract_value: '', deadline: '' });
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [newStageName, setNewStageName] = useState('');
  const [projectFiles, setProjectFiles] = useState<ProjectDocument[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProjectId, setUploadProjectId] = useState('');
  const fileInputRef = React.useRef<HTMLInputElement>(null);
  const [isNewEventOpen, setIsNewEventOpen] = useState(false);
  const [newEvent, setNewEvent] = useState({ title: '', event_date: '', start_time: '', project_id: '' });
  const [editingEvent, setEditingEvent] = useState<EditingEvent | null>(null);
  const [logForm, setLogForm] = useState({ project_id: '', log_text: '', materials: '' });
  const [isSavingLog, setIsSavingLog] = useState(false);
  const [expandedLead, setExpandedLead] = useState<string | null>(null);
  const [leadNotes, setLeadNotes] = useState<Record<string, string>>({});
  const [chatMsg, setChatMsg] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const chatFileRef = React.useRef<HTMLInputElement>(null);
  const chatEndRef = React.useRef<HTMLDivElement>(null);
  const mediaRecorderRef = React.useRef<MediaRecorder | null>(null);
  const audioChunksRef = React.useRef<Blob[]>([]);
  const [profileEditing, setProfileEditing] = useState(false);
  const [profileForm, setProfileForm] = useState<Record<string, string>>({});
  const [profileSaving, setProfileSaving] = useState(false);
  const [passwordForm, setPasswordForm] = useState({ newPass: '', confirmPass: '' });
  const [passwordSaving, setPasswordSaving] = useState(false);
  const profileAvatarRef = React.useRef<HTMLInputElement>(null);

  // Notifications
  const [notifications, setNotifications] = useState<any[]>([]);
  const [notifOpen, setNotifOpen] = useState(false);
  const unreadCount = notifications.filter((n: any) => !n.read).length;
  
  const showToast = (title: string, msg: string, type: 'error' | 'success' = 'success') => {
    setToastMessage({title, msg, type});
    setTimeout(() => setToastMessage(null), 4000);
  };

  useEffect(() => {
    async function fetchData() {
      setLoadingDb(true);
      
      const { data: { user: currentUser } } = await supabase.auth.getUser();
      if (!currentUser) { navigate('/', { replace: true }); return; }
      setUser(currentUser);
      // ROLE GUARD: only parceiro can access this dashboard
      const { data: roleProfile } = await supabase.from('profiles').select('role').eq('id', currentUser.id).single();
      if (roleProfile && roleProfile.role && roleProfile.role !== 'parceiro') {
        if (roleProfile.role === 'admin') { navigate('/admin', { replace: true }); return; }
        if (roleProfile.role === 'cliente') { navigate('/client', { replace: true }); return; }
        navigate('/', { replace: true }); return;
      }
      // Parallel fetch all data at once for faster loading
      const [pRes, lRes, sRes, eRes, mRes, adminRes, clientsRes, logRes] = await Promise.all([
        supabase.from('projects').select('*'),
        supabase.from('leads').select('*'),
        supabase.from('stages').select('*'),
        supabase.from('calendar_events').select('*'),
        supabase.from('messages').select('*').or(`sender_id.eq.${currentUser.id},receiver_id.eq.${currentUser.id}`).order('created_at', { ascending: true }),
        supabase.from('profiles').select('*').eq('role', 'admin'),
        supabase.from('clients').select('*').order('name'),
        supabase.from('daily_logs').select('*'),
      ]);

      if (pRes.data) setProjects(pRes.data);
      if (lRes.data) setLeads(lRes.data);
      if (sRes.data) setStages(sRes.data);
      if (eRes.data) setEvents(eRes.data);
      if (mRes.data) setMessages(mRes.data);
      if (adminRes.data && adminRes.data.length > 0) setAdminUser(adminRes.data[0]);
      if (clientsRes.data) setClients(clientsRes.data);
      if (logRes.data) setLogs(logRes.data);

      // Load notifications
      const { data: notifs } = await supabase.from('notifications').select('*').eq('user_id', currentUser.id).order('created_at', { ascending: false }).limit(20);
      if (notifs) setNotifications(notifs);

      setLoadingDb(false);
    }
    fetchData();
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme === 'light' ? 'light' : '');
  }, [theme]);

  const toggleTheme = () => {
    const newTheme = theme === 'dark' ? 'light' : 'dark';
    setTheme(newTheme);
    localStorage.setItem('appTheme', newTheme);
    document.documentElement.setAttribute('data-theme', newTheme);
  };
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const { t, lang, setLang } = useLanguage();
  const navItemClass = (tab: string) => `ni ${activeTab === tab ? 'active' : ''}`;
  const navTo = (tab: string) => { setActiveTab(tab); setSidebarOpen(false); };

  const handleCreateProject = () => {
    setIsNewProjectOpen(true);
  };

  const submitProjectForm = async (e?: any) => {
    if (e) e.preventDefault();
    if (!newProjectForm.name) {
      showToast("Aten├º├úo", "Por favor, preencha o Nome do Projeto.", "error");
      return;
    }
    setIsSubmittingProject(true);
    try {
      const { name, service_type, contract_value, deadline } = newProjectForm;
      
      const { error } = await supabase.from('projects').insert([{ 
        name, 
        service_type: service_type || 'Reforma Residencial', 
        status: 'active', 
        progress: 0,
        contract_value: contract_value ? parseInt(contract_value.toString()) : 0,
        deadline: deadline || null
      }]);
      
      if (error) {
         console.error('Supabase Insert Error:', error);
         showToast("Erro do Banco de Dados", error.message, "error");
      } else {
         showToast("Sucesso", "Projeto criado com sucesso!", "success");
         setIsNewProjectOpen(false);
         setNewProjectForm({ name: '', service_type: 'Reforma', contract_value: '', deadline: '' });
         // Refresh projects list from database
         const { data: refreshed } = await supabase.from('projects').select('*');
         if (refreshed) setProjects(refreshed);
      }
    } catch (err: any) {
      console.error('Unexpected Form Error:', err);
      showToast("Falha Cr├¡tica", err.message, "error");
    } finally {
      setIsSubmittingProject(false);
    }
  };

  // === STAGES FUNCTIONS ===
  const projectStages = selectedProject ? stages.filter((s: any) => s.project_id === selectedProject.id) : [];

  const addStage = async () => {
    if (!newStageName.trim() || !selectedProject) return;
    const nextOrder = projectStages.length + 1;
    try {
      const { data, error } = await supabase.from('stages').insert([{
        project_id: selectedProject.id,
        name: newStageName.trim(),
        status: 'pending',
        order_index: nextOrder
      }]).select().single();
      if (error) { showToast('Erro', error.message, 'error'); return; }
      setStages(prev => [...prev, data]);
      setNewStageName('');
      showToast('Sucesso', 'Etapa adicionada!', 'success');
    } catch (err: any) { showToast('Erro', err.message, 'error'); }
  };

  const toggleStage = async (stageId: string, currentStatus: string) => {
    const newStatus = currentStatus === 'completed' ? 'pending' : 'completed';
    setStages(prev => prev.map(s => s.id === stageId ? { ...s, status: newStatus } : s));
    await supabase.from('stages').update({ status: newStatus }).eq('id', stageId);
    // Recalculate progress
    const updatedStages = stages.map(s => s.id === stageId ? { ...s, status: newStatus } : s).filter(s => s.project_id === selectedProject?.id);
    if (updatedStages.length > 0 && selectedProject) {
      const completed = updatedStages.filter(s => s.status === 'completed').length;
      const progress = Math.round((completed / updatedStages.length) * 100);
      await supabase.from('projects').update({ progress }).eq('id', selectedProject.id);
      setProjects(prev => prev.map(p => p.id === selectedProject.id ? { ...p, progress } : p));
      setSelectedProject((prev: any) => prev ? { ...prev, progress } : prev);
    }
  };

  const deleteStage = async (stageId: string) => {
    setStages(prev => prev.filter(s => s.id !== stageId));
    await supabase.from('stages').delete().eq('id', stageId);
    // Recalculate progress
    const remaining = stages.filter(s => s.id !== stageId && s.project_id === selectedProject?.id);
    if (selectedProject) {
      const completed = remaining.filter(s => s.status === 'completed').length;
      const progress = remaining.length > 0 ? Math.round((completed / remaining.length) * 100) : 0;
      await supabase.from('projects').update({ progress }).eq('id', selectedProject.id);
      setProjects(prev => prev.map(p => p.id === selectedProject.id ? { ...p, progress } : p));
      setSelectedProject((prev: any) => prev ? { ...prev, progress } : prev);
    }
    showToast('Removida', 'Etapa removida.', 'success');
  };

  // === FILE UPLOAD FUNCTIONS ===
  const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL || 'https://tyeaqluofishcvhvpwrg.supabase.co';

  const loadProjectFiles = async (projectId?: string) => {
    const pid = projectId || uploadProjectId;
    if (!pid) return;
    const { data, error } = await supabase.from('project_documents').select('*').eq('project_id', pid).order('created_at', { ascending: false });
    if (!error && data) setProjectFiles(data);
  };

  useEffect(() => { if (uploadProjectId) loadProjectFiles(uploadProjectId); }, [uploadProjectId]);

  const handleFileUpload = async (files: FileList | null) => {
    if (!files || files.length === 0 || !uploadProjectId) {
      if (!uploadProjectId) showToast('Aten├º├úo', 'Selecione um projeto antes de enviar arquivos.', 'error');
      return;
    }
    setIsUploading(true);
    let successCount = 0;
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const ext = file.name.split('.').pop();
      const path = `${uploadProjectId}/${Date.now()}_${i}.${ext}`;
      const { error: uploadErr } = await supabase.storage.from('project-files').upload(path, file, { cacheControl: '3600', upsert: false });
      if (uploadErr) { showToast('Erro', `Falha ao enviar ${file.name}: ${uploadErr.message}`, 'error'); continue; }
      const publicUrl = `${SUPABASE_URL}/storage/v1/object/public/project-files/${path}`;
      const { error: dbErr } = await supabase.from('project_documents').insert([{
        project_id: uploadProjectId,
        file_url: publicUrl,
        file_name: file.name,
        file_type: file.type
      }]);
      if (!dbErr) successCount++;
    }
    if (successCount > 0) showToast('Sucesso', `${successCount} arquivo(s) enviado(s)!`, 'success');
    await loadProjectFiles();
    setIsUploading(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const deleteFile = async (fileRecord: any) => {
    const pathMatch = fileRecord.file_url?.match(/project-files\/(.+)$/);
    if (pathMatch) await supabase.storage.from('project-files').remove([pathMatch[1]]);
    await supabase.from('project_documents').delete().eq('id', fileRecord.id);
    setProjectFiles(prev => prev.filter(f => f.id !== fileRecord.id));
    showToast('Removido', 'Arquivo removido.', 'success');
  };

  const getFileIcon = (type: string) => {
    if (type?.startsWith('image/')) return '­ƒû╝´©Å';
    if (type?.includes('pdf')) return '­ƒôä';
    if (type?.includes('word') || type?.includes('document')) return '­ƒôØ';
    if (type?.includes('sheet') || type?.includes('excel')) return '­ƒôè';
    return '­ƒôÄ';
  };

  // === CALENDAR FUNCTIONS ===
  const addEvent = async () => {
    if (!newEvent.title || !newEvent.event_date) {
      showToast('Aten├º├úo', 'Preencha o t├¡tulo e a data.', 'error');
      return;
    }
    try {
      const { data, error } = await supabase.from('calendar_events').insert([{
        title: newEvent.title,
        event_date: newEvent.event_date,
        start_time: newEvent.start_time || null,
        lead_id: null
      }]).select().single();
      if (error) { showToast('Erro', error.message, 'error'); return; }
      setEvents(prev => [...prev, data]);
      setNewEvent({ title: '', event_date: '', start_time: '', project_id: '' });
      setIsNewEventOpen(false);
      showToast('Sucesso', 'Atividade agendada!', 'success');
    } catch (err: any) { showToast('Erro', err.message, 'error'); }
  };

  const deleteEvent = async (eventId: string) => {
    await supabase.from('calendar_events').delete().eq('id', eventId);
    setEvents(prev => prev.filter(e => e.id !== eventId));
    showToast('Removido', 'Evento removido.', 'success');
  };

  const handleEditEventSave = async () => {
    if (!editingEvent) return;
    try {
      const { error } = await supabase.from('calendar_events').update({
        event_date: editingEvent.date,
        start_time: editingEvent.time,
        title: editingEvent.title,
      }).eq('id', editingEvent.id);
      if (error) throw error;
      setEvents(prev => prev.map(e => e.id === editingEvent.id ? { ...e, event_date: editingEvent.date, start_time: editingEvent.time, title: editingEvent.title } : e));
      showToast('Atualizado', 'Evento atualizado com sucesso!', 'success');
      setEditingEvent(null);
    } catch (err: any) {
      console.error(err);
      showToast('Erro', 'Erro ao atualizar evento.', 'error');
    }
  };

  const handleEditEventDelete = async () => {
    if (!editingEvent) return;
    if (confirm(`Deseja excluir "${editingEvent.title}"?`)) {
      await deleteEvent(editingEvent.id);
      setEditingEvent(null);
    }
  };

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const endOfWeek = new Date(today);
  endOfWeek.setDate(endOfWeek.getDate() + 7);

  const todayEvents = events.filter(e => {
    const d = new Date(e.event_date);
    d.setHours(0, 0, 0, 0);
    return d.getTime() === today.getTime();
  });
  const weekEvents = events.filter(e => {
    const d = new Date(e.event_date);
    d.setHours(0, 0, 0, 0);
    return d > today && d <= endOfWeek;
  });
  const futureEvents = events.filter(e => {
    const d = new Date(e.event_date);
    d.setHours(0, 0, 0, 0);
    return d > endOfWeek;
  }).sort((a, b) => new Date(a.event_date).getTime() - new Date(b.event_date).getTime());

  // === LOG FUNCTIONS ===
  const submitLog = async () => {
    if (!logForm.project_id) { showToast('Aten├º├úo', 'Selecione um projeto.', 'error'); return; }
    if (!logForm.log_text.trim()) { showToast('Aten├º├úo', 'Descreva as atividades realizadas.', 'error'); return; }
    setIsSavingLog(true);
    try {
      const fullText = logForm.materials.trim()
        ? `${logForm.log_text.trim()}\n\n­ƒº▒ Materiais: ${logForm.materials.trim()}`
        : logForm.log_text.trim();
      const { data, error } = await supabase.from('daily_logs').insert([{
        project_id: logForm.project_id,
        log_text: fullText
      }]).select().single();
      if (error) { showToast('Erro', error.message, 'error'); setIsSavingLog(false); return; }
      setLogs(prev => [data, ...prev]);
      setLogForm({ project_id: logForm.project_id, log_text: '', materials: '' });
      showToast('Salvo', 'Log do dia registrado com sucesso!', 'success');
    } catch (err: any) { showToast('Erro', err.message, 'error'); }
    setIsSavingLog(false);
  };

  const deleteLog = async (logId: string) => {
    await supabase.from('daily_logs').delete().eq('id', logId);
    setLogs(prev => prev.filter(l => l.id !== logId));
    showToast('Removido', 'Log removido.', 'success');
  };

  const getProjectName = (projectId: string) => {
    const p = projects.find((proj: any) => proj.id === projectId);
    return p ? p.name : 'Projeto';
  };

  // === LEAD FUNCTIONS ===
  const updateLeadStatus = async (leadId: string, newStatus: string) => {
    const { error } = await supabase.from('leads').update({ status: newStatus, updated_at: new Date().toISOString() }).eq('id', leadId);
    if (error) { showToast('Erro', error.message, 'error'); return; }
    setLeads(prev => prev.map((l: any) => l.id === leadId ? { ...l, status: newStatus } : l));
    showToast('Atualizado', `Status alterado para "${newStatus}".`, 'success');
  };

  const saveLeadNotes = async (leadId: string) => {
    const note = leadNotes[leadId];
    if (note === undefined) return;
    const { error } = await supabase.from('leads').update({ notes: note, updated_at: new Date().toISOString() }).eq('id', leadId);
    if (error) { showToast('Erro', error.message, 'error'); return; }
    setLeads(prev => prev.map((l: any) => l.id === leadId ? { ...l, notes: note } : l));
    showToast('Salvo', 'Observa├º├Áes salvas.', 'success');
  };

  const deleteLead = async (leadId: string) => {
    await supabase.from('leads').delete().eq('id', leadId);
    setLeads(prev => prev.filter((l: any) => l.id !== leadId));
    showToast('Removido', 'Lead removido.', 'success');
  };

  const getUrgencyColor = (u: string) => {
    if (u === 'alta' || u === 'hot') return 'var(--red)';
    if (u === 'media' || u === 'warm') return 'var(--orange)';
    return 'var(--blue)';
  };

  const getStatusColor = (s: string) => {
    if (s === 'Convertido') return 'var(--green)';
    if (s === 'Perdido') return 'var(--red)';
    if (s === 'Proposta Enviada' || s === 'Reuni├úo Agendada') return 'var(--gold)';
    return 'var(--t3)';
  };

  const leadStatuses = ['Novo', 'Em Contato', 'Reuni├úo Agendada', 'Proposta Enviada', 'Convertido', 'Perdido'];

  // === CHAT FUNCTIONS ===

  // Realtime subscription
  useEffect(() => {
    const channel = supabase.channel('messages-realtime')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'messages' }, (payload: any) => {
        const msg = payload.new;
        setMessages(prev => {
          if (prev.some((m: any) => m.id === msg.id)) return prev;
          return [...prev, msg];
        });
        // Add in-app notification for messages received by this user
        if (msg.receiver_id === user?.id) {
          setNotifications(prev => [{ id: 'msg-' + msg.id, title: '­ƒÆ¼ Nova mensagem', body: msg.content?.substring(0, 80) || 'Nova mensagem recebida', read: false, created_at: new Date().toISOString() }, ...prev]);
        }
      })
      .subscribe();

    // Realtime notifications
    const notifChannel = supabase.channel('partner-notifications')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'notifications' }, (payload) => {
        const notif = payload.new as any;
        setNotifications(prev => [notif, ...prev]);
        setNotifOpen(true);
        // Browser push notification
        if ('Notification' in window && Notification.permission === 'granted') {
          new Notification(notif.title, { body: notif.body, icon: '/bravo-logo.png', tag: 'notif-' + notif.id });
        }
      })
      .subscribe();

    // Request notification permission
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }

    return () => { supabase.removeChannel(channel); supabase.removeChannel(notifChannel); };
  }, []);

  // Auto-scroll on new messages
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (content: string, ext?: string, payloadData?: any) => {
    if (!content.trim() && !payloadData) return;
    const receiverId = chatTab === 'admin' ? (adminUser?.id || null) : (selectedChatClient?.id || null);
    const pl = payloadData ? { ...payloadData, msg_type: ext || 'text' } : { msg_type: 'text' };
    const { data, error } = await supabase.from('messages').insert([{
      sender_id: user?.id || null,
      receiver_id: receiverId,
      content: content.trim() || '­ƒôÄ',
      payload: pl
    }]).select().single();
    if (error) { showToast('Erro', error.message, 'error'); return; }
    setMessages(prev => {
      if (prev.some((m: any) => m.id === data.id)) return prev;
      return [...prev, data];
    });
    setChatMsg('');
  };

  const sendChatFile = async (files: FileList | null) => {
    if (!files || files.length === 0) return;
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const fext = file.name.split('.').pop();
      const path = `chat/${Date.now()}_${i}.${fext}`;
      const { error: upErr } = await supabase.storage.from('project-files').upload(path, file, { cacheControl: '3600', upsert: false });
      if (upErr) { showToast('Erro', upErr.message, 'error'); continue; }
      const url = `${SUPABASE_URL}/storage/v1/object/public/project-files/${path}`;
      const isImg = file.type.startsWith('image/');
      await sendMessage(isImg ? '­ƒû╝´©Å Photo' : `­ƒôÄ ${file.name}`, isImg ? 'image' : 'file', { url, name: file.name, type: file.type });
    }
    if (chatFileRef.current) chatFileRef.current.value = '';
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const recorder = new MediaRecorder(stream);
      audioChunksRef.current = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) audioChunksRef.current.push(e.data); };
      recorder.onstop = async () => {
        stream.getTracks().forEach(t => t.stop());
        const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const path = `chat/audio_${Date.now()}.webm`;
        const { error: upErr } = await supabase.storage.from('project-files').upload(path, blob, { cacheControl: '3600', upsert: false, contentType: 'audio/webm' });
        if (upErr) { showToast('Erro', upErr.message, 'error'); return; }
        const url = `${SUPABASE_URL}/storage/v1/object/public/project-files/${path}`;
        await sendMessage('­ƒÄñ Audio message', 'audio', { url, name: 'audio.webm', type: 'audio/webm' });
      };
      mediaRecorderRef.current = recorder;
      recorder.start();
      setIsRecording(true);
    } catch (err) { showToast('Erro', 'Permiss├úo de microfone negada.', 'error'); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
    }
    setIsRecording(false);
  };

  const channelMessages = messages.filter((m: any) => {
    if (!user) return false;
    if (chatTab === 'admin') {
      // Messages between me and admin
      return (m.sender_id === user.id && m.receiver_id === adminUser?.id) ||
             (m.sender_id === adminUser?.id && m.receiver_id === user.id);
    } else if (selectedChatClient) {
      // Messages between me and the selected client
      return (m.sender_id === user.id && m.receiver_id === selectedChatClient.id) ||
             (m.sender_id === selectedChatClient.id && m.receiver_id === user.id);
    }
    return false;
  });

  // Derive chat client list from messages (only show clients with active conversations)
  const chatClients = React.useMemo(() => {
    if (!user) return [];
    const contactIds = new Set<string>();
    messages.forEach((m: any) => {
      if (m.sender_id === user.id && m.receiver_id && m.receiver_id !== adminUser?.id) contactIds.add(m.receiver_id);
      if (m.receiver_id === user.id && m.sender_id && m.sender_id !== adminUser?.id) contactIds.add(m.sender_id);
    });
    return Array.from(contactIds).map(id => {
      const client = clients.find((c: any) => c.id === id);
      return client || { id, name: 'Cliente', email: '', phone: '' };
    });
  }, [messages, user, adminUser, clients]);

  // === PROFILE FUNCTIONS ===
  const [profileData, setProfileData] = useState<Record<string, string> | null>(null);

  useEffect(() => {
    if (!user?.id) return;
    supabase.from('profiles').select('*').eq('id', user.id).single().then(async ({ data, error }) => {
      if (data) {
        setProfileData(data);
        setProfileForm(data);
      } else {
        // Profile row doesn't exist, create it
        const newProfile = {
          id: user.id,
          full_name: user.user_metadata?.full_name || '',
          role: 'partner',
          notifications_email: true,
          notifications_sms: true
        };
        await supabase.from('profiles').upsert([newProfile]);
        setProfileData(newProfile);
        setProfileForm(newProfile);
      }
    });
  }, [user]);

  const saveProfile = async () => {
    if (!user?.id) return;
    setProfileSaving(true);
    const { error } = await supabase.from('profiles').upsert({
      id: user.id,
      full_name: profileForm.full_name,
      phone: profileForm.phone,
      specialty: profileForm.specialty,
      license_number: profileForm.license_number,
      company_name: profileForm.company_name,
      city: profileForm.city,
      state: profileForm.state,
      bio: profileForm.bio,
      notifications_email: profileForm.notifications_email,
      notifications_sms: profileForm.notifications_sms
    });
    setProfileSaving(false);
    if (error) { showToast('Error', error.message, 'error'); return; }
    setProfileData({...profileData, ...profileForm});
    setProfileEditing(false);
    showToast('Saved', 'Profile updated successfully!', 'success');
  };

  const uploadAvatar = async (files: FileList | null) => {
    if (!files || !files[0] || !user?.id) return;
    const file = files[0];
    const ext = file.name.split('.').pop();
    const path = `avatars/${user.id}.${ext}`;
    const { error: upErr } = await supabase.storage.from('project-files').upload(path, file, { cacheControl: '3600', upsert: true });
    if (upErr) { showToast('Error', upErr.message, 'error'); return; }
    const url = `${SUPABASE_URL}/storage/v1/object/public/project-files/${path}?t=${Date.now()}`;
    await supabase.from('profiles').update({ avatar_url: url }).eq('id', user.id);
    setProfileData({...profileData, avatar_url: url});
    setProfileForm({...profileForm, avatar_url: url});
    showToast('Saved', 'Avatar updated!', 'success');
  };

  const changePassword = async () => {
    if (passwordForm.newPass.length < 6) { showToast('Error', 'Password must be at least 6 characters.', 'error'); return; }
    if (passwordForm.newPass !== passwordForm.confirmPass) { showToast('Error', 'Passwords do not match.', 'error'); return; }
    setPasswordSaving(true);
    const { error } = await supabase.auth.updateUser({ password: passwordForm.newPass });
    setPasswordSaving(false);
    if (error) { showToast('Error', error.message, 'error'); return; }
    setPasswordForm({ newPass: '', confirmPass: '' });
    showToast('Success', 'Password changed successfully!', 'success');
  };

  const toggleNotif = async (key: string, val: boolean) => {
    if (!user?.id) return;
    setProfileForm({...profileForm, [key]: val});
    await supabase.from('profiles').update({ [key]: val }).eq('id', user.id);
    setProfileData({...profileData, [key]: val});
    showToast('Saved', 'Notification preference updated.', 'success');
  };

  return (
    <div className="partner-app">
      {/* SIDEBAR */}
      <PartnerSidebar
        theme={theme}
        profileData={profileData}
        user={user}
        activeTab={activeTab}
        navTo={navTo}
        projectsCount={projects.length}
        leadsCount={leads.length}
        t={t as any}
        sidebarOpen={sidebarOpen}
        setSidebarOpen={setSidebarOpen}
        handleLogout={async () => { localStorage.removeItem('partnerActiveTab'); await supabase.auth.signOut(); window.location.href = '/'; }}
      />

      {/* MAIN */}
      <div className="main">
        {toastMessage && (
          <div style={{position: 'fixed', bottom: 30, right: 30, background: toastMessage.type === 'error' ? 'var(--red)' : 'var(--green)', color: '#fff', padding: '15px 20px', borderRadius: '8px', zIndex: 9999, boxShadow: '0 4px 15px rgba(0,0,0,0.3)', display: 'flex', flexDirection: 'column', gap: '5px'}}>
            <strong style={{fontFamily: "'Syne', sans-serif"}}>{toastMessage.title}</strong>
            <span style={{fontSize: '0.85rem'}}>{toastMessage.msg}</span>
          </div>
        )}
        <PartnerHeader
          theme={theme}
          toggleTheme={toggleTheme}
          activeTab={activeTab}
          sidebarOpen={sidebarOpen}
          setSidebarOpen={setSidebarOpen}
          t={t as any}
          unreadCount={unreadCount}
          notifOpen={notifOpen}
          setNotifOpen={setNotifOpen}
          notifications={notifications}
          setNotifications={setNotifications}
          user={user}
        />
        <div className="content">
          {/* DASHBOARD */}
          {activeTab === 'dashboard' && (
            <PartnerHomeTab
              projects={projects}
              stages={stages}
              messages={messages}
              leads={leads}
              events={events}
              logs={logs}
              setActiveTab={setActiveTab}
            />
          )}

          {/* PROJECTS */}
          {activeTab === 'projects' && (
            <PartnerProjectsTab
              handleCreateProject={handleCreateProject}
              setSelectedProject={setSelectedProject}
              setActiveTab={setActiveTab}
            />
          )}

          {activeTab === 'stages' && (
            <PartnerStagesTab
              projects={projects}
              selectedProject={selectedProject}
              setSelectedProject={setSelectedProject}
              projectStages={projectStages}
              newStageName={newStageName}
              setNewStageName={setNewStageName}
              addStage={addStage}
              toggleStage={toggleStage}
              deleteStage={deleteStage}
              showToast={showToast}
              setUploadProjectId={setUploadProjectId}
              setActiveTab={setActiveTab}
            />
          )}

          {/* CALENDAR */}
          {activeTab === 'calendar' && (
            <PartnerCalendarTab projects={projects} showToast={showToast} />
          )}

          {/* DAILY LOG */}
          {activeTab === 'dailylog' && (
            <PartnerDailyLogTab
              projects={projects}
              logs={logs}
              logForm={logForm}
              setLogForm={setLogForm}
              submitLog={submitLog}
              isSavingLog={isSavingLog}
              getProjectName={getProjectName}
              deleteLog={deleteLog}
            />
          )}

          {/* LEADS */}
          {activeTab === 'leads' && (
            <PartnerLeadsTab
              leads={leads}
              loadingDb={loadingDb}
              expandedLead={expandedLead}
              setExpandedLead={setExpandedLead}
              getUrgencyColor={getUrgencyColor}
              getStatusColor={getStatusColor}
              leadStatuses={leadStatuses}
              updateLeadStatus={updateLeadStatus}
              leadNotes={leadNotes}
              setLeadNotes={setLeadNotes}
              saveLeadNotes={saveLeadNotes}
              deleteLead={deleteLead}
            />
          )}

          {/* CHAT */}
          {activeTab === 'chat' && (
            <PartnerChatTab
              user={user}
              chatTab={chatTab}
              setChatTab={setChatTab}
              messages={messages}
              chatClients={chatClients}
              selectedChatClient={selectedChatClient}
              setSelectedChatClient={setSelectedChatClient}
              setDeleteConfirmClient={setDeleteConfirmClient}
              channelMessages={channelMessages}
              chatEndRef={chatEndRef}
              chatFileRef={chatFileRef}
              sendChatFile={sendChatFile}
              isRecording={isRecording}
              stopRecording={stopRecording}
              startRecording={startRecording}
              chatMsg={chatMsg}
              setChatMsg={setChatMsg}
              sendMessage={sendMessage}
            />
          )}

          {/* Delete conversation confirmation popup */}
          {deleteConfirmClient && (
            <div style={{position:'fixed',top:0,left:0,right:0,bottom:0,background:'rgba(0,0,0,0.6)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:9999}} onClick={() => setDeleteConfirmClient(null)}>
              <div style={{background:'var(--bg2)',border:'1px solid var(--b)',borderRadius:12,padding:'28px 32px',maxWidth:400,width:'90%',boxShadow:'0 20px 60px rgba(0,0,0,0.5)'}} onClick={e => e.stopPropagation()}>
                <div style={{fontSize:'1.2rem',marginBottom:6}}>­ƒùæ´©Å</div>
                <div style={{fontFamily:"'Syne',sans-serif",fontWeight:700,fontSize:'1rem',marginBottom:8}}>Apagar conversa?</div>
                <div style={{color:'var(--t2)',fontSize:'0.85rem',marginBottom:20,lineHeight:1.5}}>
                  Tem certeza que deseja apagar toda a conversa com <b style={{color:'var(--gold)'}}>{deleteConfirmClient.name || 'este cliente'}</b>? Esta a├º├úo n├úo pode ser desfeita.
                </div>
                <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                  <button className="btn ghost" onClick={() => setDeleteConfirmClient(null)}>Cancelar</button>
                  <button className="btn" style={{background:'var(--red)',color:'#fff',border:'none'}} onClick={async () => {
                    // Delete all messages between partner and this client
                    await supabase.from('messages').delete().or(
                      `and(sender_id.eq.${user?.id},receiver_id.eq.${deleteConfirmClient.id}),and(sender_id.eq.${deleteConfirmClient.id},receiver_id.eq.${user?.id})`
                    );
                    // Remove from local state
                    setMessages(prev => prev.filter(m =>
                      !((m.sender_id === user?.id && m.receiver_id === deleteConfirmClient.id) ||
                        (m.sender_id === deleteConfirmClient.id && m.receiver_id === user?.id))
                    ));
                    // Remove client from sidebar list
                    setClients(prev => prev.filter(c => c.id !== deleteConfirmClient.id));
                    // If this was the selected chat, deselect
                    if (selectedChatClient?.id === deleteConfirmClient.id) {
                      setSelectedChatClient(null);
                      setChatTab('admin');
                    }
                    setDeleteConfirmClient(null);
                    showToast('Sucesso', 'Conversa apagada.', 'success');
                  }}>Apagar</button>
                </div>
              </div>
            </div>
          )}

          {/* UPLOADS */}
          {activeTab === 'uploads' && (
            <PartnerUploadsTab
              projects={projects}
              uploadProjectId={uploadProjectId}
              setUploadProjectId={setUploadProjectId}
              projectFiles={projectFiles}
              isUploading={isUploading}
              fileInputRef={fileInputRef}
              handleFileUpload={handleFileUpload}
              deleteFile={deleteFile}
              getFileIcon={getFileIcon}
            />
          )}

          {/* PROFILE */}
          {activeTab === 'profile' && (
            <PartnerProfileTab
              user={user}
              profileData={profileData}
              profileEditing={profileEditing}
              setProfileEditing={setProfileEditing}
              profileForm={profileForm}
              setProfileForm={setProfileForm}
              profileSaving={profileSaving}
              saveProfile={saveProfile}
              profileAvatarRef={profileAvatarRef}
              uploadAvatar={uploadAvatar}
              passwordForm={passwordForm}
              setPasswordForm={setPasswordForm}
              passwordSaving={passwordSaving}
              changePassword={changePassword}
              toggleNotif={toggleNotif}
              t={t}
              lang={lang}
              setLang={setLang}
            />
          )}

        </div>
      </div>



      {/* NOVO PROJETO MODAL */}
      {isNewProjectOpen && (
        <div className="modal-overlay open" onClick={() => setIsNewProjectOpen(false)}>
          <div className="modal" onClick={e => e.stopPropagation()} style={{maxWidth: '450px'}}>
            <div className="modal-head">
              <div className="modal-title">Criar Novo Projeto</div>
              <button className="dclose" onClick={() => setIsNewProjectOpen(false)}>Ô£ò</button>
            </div>
            <form onSubmit={submitProjectForm}>
              <div className="modal-body">
                <div className="f-row" style={{marginBottom: '15px'}}>
                  <div style={{width: '100%'}}>
                    <label className="f-label">Nome do Projeto *</label>
                    <input required type="text" className="f-inp" placeholder="Ex: Reforma Johnson" value={newProjectForm.name} onChange={e => setNewProjectForm({...newProjectForm, name: e.target.value})} />
                  </div>
                </div>
                <div className="f-row" style={{marginBottom: '15px'}}>
                  <div style={{width: '100%'}}>
                    <label className="f-label">Tipo de Servi├ºo *</label>
                    <select required className="f-inp" value={newProjectForm.service_type} onChange={e => setNewProjectForm({...newProjectForm, service_type: e.target.value})}>
                      <option value="Reforma Completa">Reforma Completa</option>
                      <option value="Bathroom Remodel">Bathroom Remodel</option>
                      <option value="Kitchen Remodel">Kitchen Remodel</option>
                      <option value="Pintura e Acabamento">Pintura e Acabamento</option>
                      <option value="Outro">Outro</option>
                    </select>
                  </div>
                </div>
                <div className="f-row" style={{marginBottom: '20px', display: 'flex', gap: '15px'}}>
                  <div style={{flex: 1}}>
                    <label className="f-label" style={{whiteSpace: 'nowrap'}}>Valor Estimado ($)</label>
                    <input type="number" className="f-inp" placeholder="Ex: 25000" value={newProjectForm.contract_value} onChange={e => setNewProjectForm({...newProjectForm, contract_value: e.target.value})} />
                  </div>
                  <div style={{flex: 1}}>
                    <label className="f-label" style={{whiteSpace: 'nowrap'}}>Prazo de Entrega</label>
                    <input type="date" className="f-inp" value={newProjectForm.deadline} onChange={e => setNewProjectForm({...newProjectForm, deadline: e.target.value})} />
                  </div>
                </div>
                <div style={{display: 'flex', gap: '15px', marginTop: '30px', justifyContent: 'center'}}>
                   <button type="button" className="btn ghost" style={{flex: 1, padding: '12px', fontSize: '0.95rem', display: 'flex', justifyContent: 'center', alignItems: 'center'}} onClick={() => setIsNewProjectOpen(false)} disabled={isSubmittingProject}>Cancelar</button>
                   <button type="button" className="btn gold" style={{flex: 1, padding: '12px', fontSize: '0.95rem', display: 'flex', justifyContent: 'center', alignItems: 'center'}} onClick={submitProjectForm} disabled={isSubmittingProject}>{isSubmittingProject ? 'Criando...' : 'Criar Projeto'}</button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

    </div>
  );
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { supabase } from '../lib/supabase';

const mockNavigate = vi.fn();
vi.mock('react-router-dom', async () => {
  const actual = await vi.importActual('react-router-dom');
  return { ...actual, useNavigate: () => mockNavigate };
});

describe('Login / Auth Flow', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('supabase.auth.getUser returns null when not logged in', async () => {
    (supabase.auth.getUser as any).mockResolvedValue({ data: { user: null } });

    const { data: { user } } = await supabase.auth.getUser();
    expect(user).toBeNull();
  });

  it('supabase.auth.getUser returns user when logged in', async () => {
    const mockUser = { id: 'abc-123', email: 'test@bravo.com', user_metadata: { full_name: 'Test User' } };
    (supabase.auth.getUser as any).mockResolvedValue({ data: { user: mockUser } });

    const { data: { user } } = await supabase.auth.getUser();
    expect(user).not.toBeNull();
    expect(user?.email).toBe('test@bravo.com');
    expect(user?.user_metadata?.full_name).toBe('Test User');
  });

  it('signInWithOAuth calls supabase auth correctly', async () => {
    (supabase.auth.signInWithOAuth as any).mockResolvedValue({ data: {}, error: null });

    const result = await supabase.auth.signInWithOAuth({ provider: 'google' as any });
    expect(supabase.auth.signInWithOAuth).toHaveBeenCalledWith({ provider: 'google' });
    expect(result.error).toBeNull();
  });

  it('signOut calls supabase auth correctly', async () => {
    (supabase.auth.signOut as any).mockResolvedValue({ error: null });

    const { error } = await supabase.auth.signOut();
    expect(supabase.auth.signOut).toHaveBeenCalled();
    expect(error).toBeNull();
  });

  it('role-based routing sends admin to /admin', () => {
    const route = (role: string) => {
      if (role === 'admin') return '/admin';
      if (role === 'parceiro') return '/partner';
      return '/client';
    };
    expect(route('admin')).toBe('/admin');
    expect(route('parceiro')).toBe('/partner');
    expect(route('cliente')).toBe('/client');
  });
});

import { describe, it, expect, vi } from 'vitest';

describe('Dashboard utility functions', () => {
  it('date formatting works correctly for pt-BR', () => {
    const date = new Date('2026-03-22T12:00:00');
    const formatted = date.toLocaleDateString('pt-BR', {
      weekday: 'short',
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    });
    expect(formatted).toBeTruthy();
    expect(formatted).toContain('2026');
  });

  it('Promise.all parallelizes multiple queries', async () => {
    const calls: number[] = [];
    const mockQuery = (id: number) =>
      new Promise((resolve) => {
        calls.push(id);
        setTimeout(() => resolve({ data: [] }), 10);
      });

    const results = await Promise.all([mockQuery(1), mockQuery(2), mockQuery(3)]);
    expect(results).toHaveLength(3);
    expect(calls).toEqual([1, 2, 3]);
  });

  it('status mapping returns correct labels', () => {
    const statusMap: Record<string, string> = {
      new: 'Nova / Recebida',
      contacted: 'Em Contato',
      scheduling: 'Agendamento de Vistoria',
      proposal: 'Proposta Enviada',
      closed: 'Fechado Ô£ô',
    };
    expect(statusMap['new']).toBe('Nova / Recebida');
    expect(statusMap['closed']).toBe('Fechado Ô£ô');
    expect(statusMap['unknown']).toBeUndefined();
  });

  it('urgency values are valid', () => {
    const validUrgencies = ['hot', 'warm', 'cool'];
    expect(validUrgencies).toContain('hot');
    expect(validUrgencies).toContain('warm');
    expect(validUrgencies).toContain('cool');
    expect(validUrgencies).not.toContain('unknown');
  });
});

